export { ExperimentCRDT } from './ExperimentCRDT.js';
export type { CRDTOptions, ExperimentChanges, ChangeCallback, UnsubscribeFn } from './ExperimentCRDT.js';

export { VisualCodeBinding } from './VisualCodeBinding.js';

export { PresenceManager } from './PresenceManager.js';
export type { PresenceCallback } from './PresenceManager.js';

export { CRDTPerformanceOptimizer } from './CRDTPerformanceOptimizer.js';
export type { OptimizationOptions, PerformanceMetrics } from './CRDTPerformanceOptimizer.js';

export { ConflictResolution } from './ConflictResolution.js';
export type { ConflictResolutionStrategy, ConflictResolutionResult } from './ConflictResolution.js';

export { OfflineSync } from './OfflineSync.js';
export type { OfflineChange, SyncStatusCallback } from './OfflineSync.js';

export { CollaborationTelemetry } from './CollaborationTelemetry.js';
export type { TelemetryEvent, TelemetryOptions, SessionMetrics } from './CollaborationTelemetry.js';

// Export types
export type {
  UserPresence,
  VisualChangeEvent,
  CodeChangeEvent,
  ConflictInfo,
  SyncStatus,
  CollaborationMetrics,
  ForgeScriptAST,
  CompiledExperiment,
  IEditor,
  ITimeline
} from './types.js';

