   131→   */
   132→  getDoc(): Y.Doc {
   133→    return this.doc;
   134→  }
   135→
   136→  /**
   137→   * Get awareness instance for presence features
   138→   */
   139→  getAwareness(): Y.Awareness | undefined {
   140→    return this.awareness;
   141→  }
   142→
   143→  /**
   144→   * Clean up resources
   145→   */
   146→  destroy(): void {
   147→    // Destroy all providers
   148→    this.providers.forEach(provider => {
   149→      if ('destroy' in provider) {
   150→        provider.destroy();
   151→      }
   152→    });
   153→
   154→    // Clear callbacks
   155→    this.changeCallbacks.clear();
   156→
   157→    // Destroy document
   158→    this.doc.destroy();
   159→  }
   160→
   161→  /**
   162→   * Set up observers for document changes
   163→   */
   164→  private setupChangeObservers(): void {
   165→    // Observe deep changes in the experiment map
   166→    const observer = (events: Y.YEvent<any>[], transaction: Y.Transaction) => {
   167→      // Skip if this is a remote change and we're not interested
   168→      if (transaction.origin === null) return;
   169→
   170→      const changes: ExperimentChanges[] = [];
   171→
   172→      events.forEach(event => {
   173→        event.changes.keys.forEach((change, key) => {
   174→          if (change.action === 'add') {
   175→            changes.push({
   176→              path: [key],
   177→              action: 'add',
   178→              value: this.experimentMap.get(key)
   179→            });
   180→          } else if (change.action === 'update') {
   181→            changes.push({
   182→              path: [key],
   183→              action: 'update',
   184→              value: this.experimentMap.get(key),
   185→              oldValue: change.oldValue
   186→            });
   187→          } else if (change.action === 'delete') {
   188→            changes.push({
   189→              path: [key],
   190→              action: 'delete',
   191→              oldValue: change.oldValue
   192→            });
   193→          }
   194→        });
   195→      });
   196→
   197→      // Notify all callbacks
   198→      if (changes.length > 0) {
   199→        this.changeCallbacks.forEach(callback => {
   200→          callback(changes);
   201→        });
   202→      }
   203→    };
   204→
   205→    this.experimentMap.observeDeep(observer);
   206→  }
   207→
   208→  /**
   209→   * Set a nested value in a Y.Map
   210→   */
   211→  private setNestedValue(map: Y.Map<any>, path: string[], value: any): void {
   212→    if (path.length === 0) return;
   213→
   214→    if (path.length === 1) {
   215→      map.set(path[0], value);
   216→      return;
   217→    }
   218→
   219→    const [head, ...tail] = path;
   220→    let nested = map.get(head);
   221→
   222→    if (!nested || !(nested instanceof Y.Map)) {
   223→      nested = new Y.Map();
   224→      map.set(head, nested);
   225→    }
   226→
   227→    this.setNestedValue(nested, tail, value);
   228→  }
   229→
   230→  /**
   231→   * Convert AST to experiment data structure
   232→   */
   233→  private astToExperiment(ast: ForgeScriptAST): Record<string, any> {
   234→    // This is a simplified conversion - in reality, this would be more complex
   235→    return {
   236→      metadata: ast.metadata || {},
   237→      timeline: ast.timeline || [],
   238→      conditions: ast.conditions || {},
   239→      stimuli: ast.stimuli || [],
   240→      code: ast.rawCode || ''
   241→    };
   242→  }
   243→
   244→  /**
   245→   * Convert Y.Map to CompiledExperiment
   246→   */
   247→  private experimentMapToCompiled(map: Y.Map<any>): CompiledExperiment {
   248→    // Convert Y.js structures back to plain objects
   249→    const toPlainObject = (yValue: any): any => {
   250→      if (yValue instanceof Y.Map) {
   251→        const obj: Record<string, any> = {};
   252→        yValue.forEach((value: any, key: string) => {
   253→          obj[key] = toPlainObject(value);
   254→        });
   255→        return obj;
   256→      } else if (yValue instanceof Y.Array) {
   257→        return yValue.toArray().map(toPlainObject);
   258→      } else if (yValue instanceof Y.Text) {
   259→        return yValue.toString();
   260→      }
   261→      return yValue;
   262→    };
   263→
   264→    return toPlainObject(map) as CompiledExperiment;
   265→  }
   266→}

