import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { ExperimentCRDT } from '../src/ExperimentCRDT';

describe('ExperimentCRDT', () => {
  let crdt: ExperimentCRDT;
  const experimentId = 'test-experiment-123';

  beforeEach(() => {
    // Create CRDT with mocked providers
    crdt = new ExperimentCRDT(experimentId, {
      enableWebRTC: false,
      enableWebSocket: false,
      enableIndexedDB: false
    });
  });

  afterEach(() => {
    crdt?.destroy();
  });

  describe('initialization', () => {
    it('should create a CRDT instance', () => {
      expect(crdt).toBeDefined();
      expect(crdt.getDoc()).toBeDefined();
    });

    it('should initialize with awareness when enabled', () => {
      const crdtWithAwareness = new ExperimentCRDT(experimentId, {
        awareness: true,
        enableWebRTC: false,
        enableWebSocket: false,
        enableIndexedDB: false
      });

      expect(crdtWithAwareness.getAwareness()).toBeDefined();
      crdtWithAwareness.destroy();
    });
  });

  describe('change subscriptions', () => {
    it('should subscribe to experiment changes', () => {
      const callback = vi.fn();
      const unsubscribe = crdt.onExperimentChange(callback);

      // Make a change
      crdt.updateFromVisual(['test'], 'value');

      // Callback should be called
      expect(callback).toHaveBeenCalled();

      // Unsubscribe
      unsubscribe();
      callback.mockClear();

      // Make another change
      crdt.updateFromVisual(['test2'], 'value2');

      // Callback should not be called
      expect(callback).not.toHaveBeenCalled();
    });
  });

  describe('visual updates', () => {
    it('should update from visual timeline changes', () => {
      const callback = vi.fn();
      crdt.onExperimentChange(callback);

      crdt.updateFromVisual(['timeline', 'trial1', 'duration'], 2000);

      expect(callback).toHaveBeenCalledWith(
        expect.arrayContaining([
          expect.objectContaining({
            path: expect.any(Array),
            action: expect.any(String),
            value: expect.anything()
          })
        ])
      );
    });

    it('should handle nested path updates', () => {
      crdt.updateFromVisual(['metadata', 'author', 'name'], 'Test Author');
      crdt.updateFromVisual(['metadata', 'author', 'email'], 'test@example.com');

      const experiment = crdt.getCurrentExperiment();
      expect(experiment.metadata?.author?.name).toBe('Test Author');
      expect(experiment.metadata?.author?.email).toBe('test@example.com');
    });
  });

  describe('code updates', () => {
    it('should update from AST changes', () => {
      const ast = {
        metadata: { name: 'Test Experiment' },
        timeline: [{ id: 'trial1', type: 'trial' }],
        conditions: { A: {}, B: {} },
        stimuli: [],
        rawCode: 'experiment("Test")'
      };

      crdt.updateFromCode(ast);

      const experiment = crdt.getCurrentExperiment();
      expect(experiment.metadata?.name).toBe('Test Experiment');
      expect(experiment.timeline).toHaveLength(1);
      expect(experiment.conditions).toHaveProperty('A');
      expect(experiment.conditions).toHaveProperty('B');
    });
  });

  describe('getCurrentExperiment', () => {
    it('should return the current experiment state', () => {
      crdt.updateFromVisual(['metadata', 'name'], 'My Experiment');
      crdt.updateFromVisual(['timeline'], []);

      const experiment = crdt.getCurrentExperiment();
      expect(experiment).toMatchObject({
        metadata: { name: 'My Experiment' },
        timeline: []
      });
    });

    it('should convert Y.js structures to plain objects', () => {
      crdt.updateFromVisual(['complex', 'nested', 'data'], {
        array: [1, 2, 3],
        object: { key: 'value' }
      });

      const experiment = crdt.getCurrentExperiment();
      expect(experiment.complex?.nested?.data).toEqual({
        array: [1, 2, 3],
        object: { key: 'value' }
      });
    });
  });

  describe('cleanup', () => {
    it('should clean up resources on destroy', () => {
      const callback = vi.fn();
      const unsubscribe = crdt.onExperimentChange(callback);

      crdt.destroy();

      // Verify callbacks are cleared
      crdt.updateFromVisual(['test'], 'value');
      expect(callback).not.toHaveBeenCalled();
    });
  });
});

