import { writable, derived, get } from 'svelte/store';
import type { 
  ExperimentCRDT, 
  PresenceManager, 
  UserPresence, 
  SyncStatus,
  VisualCodeBinding,
  CRDTPerformanceOptimizer,
  CollaborationTelemetry,
  OfflineSync
} from '@psyforge/collaboration';

export interface CollaborationState {
  initialized: boolean;
  experimentId: string | null;
  syncStatus: SyncStatus;
  activeUsers: UserPresence[];
  localUser: Partial<UserPresence> | null;
  performanceMetrics: {
    syncLatency: number;
    operationCount: number;
    memoryUsage: number;
  };
}

const initialState: CollaborationState = {
  initialized: false,
  experimentId: null,
  syncStatus: {
    connected: false,
    syncing: false,
    pendingChanges: 0,
    provider: 'offline'
  },
  activeUsers: [],
  localUser: null,
  performanceMetrics: {
    syncLatency: 0,
    operationCount: 0,
    memoryUsage: 0
  }
};

// Core stores
export const collaborationState = writable<CollaborationState>(initialState);

// Derived stores
export const isCollaborating = derived(
  collaborationState,
  $state => $state.initialized && $state.syncStatus.connected
);

export const collaboratorCount = derived(
  collaborationState,
  $state => $state.activeUsers.length
);

// Store collaboration instances
let crdt: ExperimentCRDT | null = null;
let presenceManager: PresenceManager | null = null;
let visualCodeBinding: VisualCodeBinding | null = null;
let performanceOptimizer: CRDTPerformanceOptimizer | null = null;
let telemetry: CollaborationTelemetry | null = null;
let offlineSync: OfflineSync | null = null;

/**
 * Initialize collaboration for an experiment
 */
export async function initializeCollaboration(
  experimentId: string,
  userInfo: Partial<UserPresence>,
  options: {
    websocketUrl?: string;
    enableTelemetry?: boolean;
  } = {}
) {
  try {
    // Clean up any existing collaboration
    await cleanupCollaboration();

    // Import collaboration modules dynamically
    const { 
      ExperimentCRDT, 
      PresenceManager,
      CRDTPerformanceOptimizer,
      CollaborationTelemetry,
      OfflineSync
    } = await import('@psyforge/collaboration');

    // Initialize CRDT
    crdt = new ExperimentCRDT(experimentId, {
      websocketUrl: options.websocketUrl,
      enableWebRTC: true,
      enableWebSocket: true,
      enableIndexedDB: true,
      awareness: true
    });

    // Initialize presence
    presenceManager = new PresenceManager(crdt);
    presenceManager.setLocalUser(userInfo);

    // Initialize performance optimizer
    performanceOptimizer = new CRDTPerformanceOptimizer(crdt, {
      batchTimeout: 50,
      maxBatchSize: 100,
      enableDeltaCompression: true
    });

    // Initialize telemetry if enabled
    if (options.enableTelemetry) {
      telemetry = new CollaborationTelemetry({
        enabled: true,
        endpoint: '/api/telemetry',
        privacyMode: true
      });
    }

    // Initialize offline sync
    offlineSync = new OfflineSync(crdt, experimentId);

    // Set up presence updates
    presenceManager.onPresenceChange((users) => {
      collaborationState.update(state => ({
        ...state,
        activeUsers: users
      }));

      telemetry?.updateActiveUsers(users.length);
    });

    // Set up sync status updates
    offlineSync.onSyncStatusChange((status) => {
      collaborationState.update(state => ({
        ...state,
        syncStatus: status
      }));
    });

    // Update state
    collaborationState.update(state => ({
      ...state,
      initialized: true,
      experimentId,
      localUser: userInfo
    }));

    // Start performance monitoring
    startPerformanceMonitoring();

    return { crdt, presenceManager };
  } catch (error) {
    console.error('Failed to initialize collaboration:', error);
    throw error;
  }
}

/**
 * Set up visual-code binding
 */
export async function setupVisualCodeBinding(
  editor: any, // Monaco editor instance
  timeline: any // Timeline canvas instance
) {
  if (!crdt) {
    throw new Error('Collaboration not initialized');
  }

  const { VisualCodeBinding } = await import('@psyforge/collaboration');

  visualCodeBinding = new VisualCodeBinding(crdt, editor, timeline);

  return visualCodeBinding;
}

/**
 * Update user cursor position
 */
export function updateCursorPosition(line: number, column: number) {
  presenceManager?.updateCursor(line, column);
}

/**
 * Update user selection
 */
export function updateSelection(
  elementId: string, 
  elementType: 'timeline' | 'trial' | 'stimulus' | 'code'
) {
  presenceManager?.updateSelection(elementId, elementType);
}

/**
 * Clear user selection
 */
export function clearSelection() {
  presenceManager?.clearSelection();
}

/**
 * Get CRDT instance
 */
export function getCRDT(): ExperimentCRDT | null {
  return crdt;
}

/**
 * Get presence manager
 */
export function getPresenceManager(): PresenceManager | null {
  return presenceManager;
}

/**
 * Batch update for performance
 */
export function batchUpdate(path: string[], value: any) {
  performanceOptimizer?.batchUpdate(path, value);
}

/**
 * Clean up collaboration
 */
export async function cleanupCollaboration() {
  // Stop performance monitoring
  stopPerformanceMonitoring();

  // Clean up instances
  visualCodeBinding?.destroy();
  presenceManager?.destroy();
  performanceOptimizer?.destroy();
  telemetry?.destroy();
  offlineSync?.destroy();
  crdt?.destroy();

  // Reset instances
  visualCodeBinding = null;
  presenceManager = null;
  performanceOptimizer = null;
  telemetry = null;
  offlineSync = null;
  crdt = null;

  // Reset state
  collaborationState.set(initialState);
}

// Performance monitoring
let performanceInterval: NodeJS.Timeout | null = null;

function startPerformanceMonitoring() {
  performanceInterval = setInterval(() => {
    if (performanceOptimizer) {
      const metrics = performanceOptimizer.getMetrics();
      const memoryInfo = performanceOptimizer.monitorMemoryUsage();

      collaborationState.update(state => ({
        ...state,
        performanceMetrics: {
          syncLatency: metrics.syncLatency,
          operationCount: metrics.operationCount,
          memoryUsage: memoryInfo.percentage
        }
      }));

      // Track metrics in telemetry
      telemetry?.trackEvent('performance.snapshot', {
        ...metrics,
        memory: memoryInfo
      });
    }
  }, 5000); // Every 5 seconds
}

function stopPerformanceMonitoring() {
  if (performanceInterval) {
    clearInterval(performanceInterval);
    performanceInterval = null;
  }
}

// Auto-cleanup on page unload
if (typeof window !== 'undefined') {
  window.addEventListener('beforeunload', () => {
    cleanupCollaboration();
  });
}

