import * as Y from 'yjs';
import { WebrtcProvider } from 'y-webrtc';
import { WebsocketProvider } from 'y-websocket';
import { IndexeddbPersistence } from 'y-indexeddb';
import { Awareness } from 'y-protocols/awareness';
import type { CompiledExperiment, ForgeScriptAST } from '@psyforge/forgescript';

export interface CRDTOptions {
  websocketUrl?: string;
  enableWebRTC?: boolean;
  enableWebSocket?: boolean;
  enableIndexedDB?: boolean;
  awareness?: boolean;
}

export interface ExperimentChanges {
  path: string[];
  action: 'add' | 'update' | 'delete';
  value?: any;
  oldValue?: any;
}

export type ChangeCallback = (changes: ExperimentChanges[]) => void;
export type UnsubscribeFn = () => void;

/**
 * ExperimentCRDT manages the CRDT document for collaborative experiment editing.
 * It provides synchronization across multiple clients using Y.js.
 */
export class ExperimentCRDT {
  private doc: Y.Doc;
  private experimentMap: Y.Map<any>;
  private providers: Array<WebrtcProvider | WebsocketProvider | IndexeddbPersistence> = [];
  private changeCallbacks: Set<ChangeCallback> = new Set();
  private awareness?: Awareness;

  constructor(
    private experimentId: string,
    options: CRDTOptions = {}
  ) {
    const {
      websocketUrl = 'wss://sync.psyforge.org',
      enableWebRTC = true,
      enableWebSocket = true,
      enableIndexedDB = true,
      awareness = true
    } = options;

    // Initialize Y.js document
    this.doc = new Y.Doc();
    this.experimentMap = this.doc.getMap('experiment');

    // Set up awareness for user presence
    if (awareness) {
      this.awareness = new Awareness(this.doc);
    }

    // Initialize providers for different sync methods
    if (enableWebRTC) {
      const webrtcProvider = new WebrtcProvider(experimentId, this.doc, {
        signaling: [websocketUrl],
        awareness: this.awareness
      });
      this.providers.push(webrtcProvider);
    }

    if (enableWebSocket) {
      const websocketProvider = new WebsocketProvider(
        websocketUrl,
        experimentId,
        this.doc,
        {
          awareness: this.awareness
        }
      );
      this.providers.push(websocketProvider);
    }

    if (enableIndexedDB) {
      const indexeddbProvider = new IndexeddbPersistence(experimentId, this.doc);
      this.providers.push(indexeddbProvider);
    }

    // Set up change observers
    this.setupChangeObservers();
  }

  /**
   * Subscribe to experiment changes
   */
  onExperimentChange(callback: ChangeCallback): UnsubscribeFn {
    this.changeCallbacks.add(callback);
    return () => {
      this.changeCallbacks.delete(callback);
    };
  }

  /**
   * Update experiment from visual timeline changes
   */
  updateFromVisual(path: string[], value: any): void {
    this.doc.transact(() => {
      this.setNestedValue(this.experimentMap, path, value);
    }, 'visual-update');
  }

  /**
   * Update experiment from code editor changes
   */
  updateFromCode(ast: ForgeScriptAST): void {
    this.doc.transact(() => {
      // Convert AST to experiment structure
      const experimentData = this.astToExperiment(ast);

      // Update the experiment map
      Object.entries(experimentData).forEach(([key, value]) => {
        this.experimentMap.set(key, value);
      });
    }, 'code-update');
  }

  /**
   * Get current experiment state
   */
  getCurrentExperiment(): CompiledExperiment {
    return this.experimentMapToCompiled(this.experimentMap);
  }

  /**
   * Get the Y.js document (for advanced use cases)
   */
  getDoc(): Y.Doc {
    return this.doc;
  }

  /**
   * Get awareness instance for presence features
   */
  getAwareness(): Y.Awareness | undefined {
    return this.awareness;
  }

  /**
   * Clean up resources
   */
  destroy(): void {
    // Destroy all providers
    this.providers.forEach(provider => {
      if ('destroy' in provider) {
        provider.destroy();
      }
    });

    // Clear callbacks
    this.changeCallbacks.clear();

    // Destroy document
    this.doc.destroy();
  }

  /**
   * Set up observers for document changes
   */
  private setupChangeObservers(): void {
    // Observe deep changes in the experiment map
    const observer = (events: Y.YEvent<any>[], transaction: Y.Transaction) => {
      // Skip if this is a remote change and we're not interested
      if (transaction.origin === null) return;

      const changes: ExperimentChanges[] = [];

      events.forEach(event => {
        event.changes.keys.forEach((change, key) => {
          if (change.action === 'add') {
            changes.push({
              path: [key],
              action: 'add',
              value: this.experimentMap.get(key)
            });
          } else if (change.action === 'update') {
            changes.push({
              path: [key],
              action: 'update',
              value: this.experimentMap.get(key),
              oldValue: change.oldValue
            });
          } else if (change.action === 'delete') {
            changes.push({
              path: [key],
              action: 'delete',
              oldValue: change.oldValue
            });
          }
        });
      });

      // Notify all callbacks
      if (changes.length > 0) {
        this.changeCallbacks.forEach(callback => {
          callback(changes);
        });
      }
    };

    this.experimentMap.observeDeep(observer);
  }

  /**
   * Set a nested value in a Y.Map
   */
  private setNestedValue(map: Y.Map<any>, path: string[], value: any): void {
    if (path.length === 0) return;

    if (path.length === 1) {
      map.set(path[0], value);
      return;
    }

    const [head, ...tail] = path;
    let nested = map.get(head);

    if (!nested || !(nested instanceof Y.Map)) {
      nested = new Y.Map();
      map.set(head, nested);
    }

    this.setNestedValue(nested, tail, value);
  }

  /**
   * Convert AST to experiment data structure
   */
  private astToExperiment(ast: ForgeScriptAST): Record<string, any> {
    // This is a simplified conversion - in reality, this would be more complex
    return {
      metadata: ast.metadata || {},
      timeline: ast.timeline || [],
      conditions: ast.conditions || {},
      stimuli: ast.stimuli || [],
      code: ast.rawCode || ''
    };
  }

  /**
   * Convert Y.Map to CompiledExperiment
   */
  private experimentMapToCompiled(map: Y.Map<any>): CompiledExperiment {
    // Convert Y.js structures back to plain objects
    const toPlainObject = (yValue: any): any => {
      if (yValue instanceof Y.Map) {
        const obj: Record<string, any> = {};
        yValue.forEach((value: any, key: string) => {
          obj[key] = toPlainObject(value);
        });
        return obj;
      } else if (yValue instanceof Y.Array) {
        return yValue.toArray().map(toPlainObject);
      } else if (yValue instanceof Y.Text) {
        return yValue.toString();
      }
      return yValue;
    };

    return toPlainObject(map) as CompiledExperiment;
  }
}

