import { describe, it, expect, beforeEach } from 'vitest';
import { ConflictResolution } from '../src/ConflictResolution';
import type { ConflictInfo } from '../src/types';

describe('ConflictResolution', () => {
  let resolver: ConflictResolution;

  beforeEach(() => {
    resolver = new ConflictResolution();
  });

  describe('automatic resolution', () => {
    it('should resolve numeric timing conflicts by using maximum value', () => {
      const conflict: ConflictInfo = {
        type: 'timing',
        path: ['timeline', 'trial1', 'duration'],
        localValue: 1000,
        remoteValue: 1500,
        autoResolvable: true
      };

      const result = resolver.resolveConflict(conflict);

      expect(result.resolved).toBe(true);
      expect(result.value).toBe(1500); // Max value
      expect(result.strategy).toBe('max-value');
      expect(result.confidence).toBeGreaterThan(0.8);
    });

    it('should resolve string conflicts by choosing non-empty value', () => {
      const conflict: ConflictInfo = {
        type: 'property',
        path: ['metadata', 'description'],
        localValue: '',
        remoteValue: 'Experiment description',
        autoResolvable: true
      };

      const result = resolver.resolveConflict(conflict);

      expect(result.resolved).toBe(true);
      expect(result.value).toBe('Experiment description');
      expect(result.strategy).toBe('non-empty');
    });

    it('should not auto-resolve boolean conflicts', () => {
      const conflict: ConflictInfo = {
        type: 'property',
        path: ['settings', 'enabled'],
        localValue: true,
        remoteValue: false,
        autoResolvable: true
      };

      const result = resolver.resolveConflict(conflict);

      expect(result.resolved).toBe(false);
      expect(result.strategy).toBe('manual-required');
    });
  });

  describe('strategy-based resolution', () => {
    it('should apply custom resolver for duration conflicts', () => {
      const conflict: ConflictInfo = {
        type: 'timing',
        path: ['trial', 'duration'],
        localValue: 1000,
        remoteValue: 2000,
        autoResolvable: false
      };

      const result = resolver.resolveConflict(conflict);

      expect(result.resolved).toBe(true);
      expect(result.value).toBe(2000); // Max value from custom resolver
      expect(result.strategy).toBe('custom');
    });

    it('should prefer local value for position conflicts', () => {
      const conflict: ConflictInfo = {
        type: 'property',
        path: ['element', 'position', 'x'],
        localValue: 100,
        remoteValue: 200,
        autoResolvable: false
      };

      const result = resolver.resolveConflict(conflict);

      expect(result.resolved).toBe(true);
      expect(result.value).toBe(100); // Local value
      expect(result.strategy).toBe('prefer-local');
    });

    it('should merge metadata objects', () => {
      const conflict: ConflictInfo = {
        type: 'property',
        path: ['metadata', 'tags'],
        localValue: { experiment: true, test: true },
        remoteValue: { experiment: true, production: false },
        autoResolvable: false
      };

      const result = resolver.resolveConflict(conflict);

      expect(result.resolved).toBe(true);
      expect(result.value).toEqual({
        experiment: true,
        production: false,
        test: true
      });
      expect(result.strategy).toBe('custom');
    });
  });

  describe('custom strategies', () => {
    it('should register and apply custom strategy', () => {
      resolver.registerStrategy('custom.path', {
        type: 'automatic',
        preference: 'remote'
      });

      const conflict: ConflictInfo = {
        type: 'property',
        path: ['custom', 'path'],
        localValue: 'local',
        remoteValue: 'remote',
        autoResolvable: false
      };

      const result = resolver.resolveConflict(conflict);

      expect(result.resolved).toBe(true);
      expect(result.value).toBe('remote');
      expect(result.strategy).toBe('prefer-remote');
    });

    it('should apply wildcard patterns', () => {
      resolver.registerStrategy('**.customField', {
        type: 'automatic',
        customResolver: (conflict) => `${conflict.localValue}-${conflict.remoteValue}`
      });

      const conflict: ConflictInfo = {
        type: 'property',
        path: ['some', 'nested', 'customField'],
        localValue: 'A',
        remoteValue: 'B',
        autoResolvable: false
      };

      const result = resolver.resolveConflict(conflict);

      expect(result.resolved).toBe(true);
      expect(result.value).toBe('A-B');
      expect(result.strategy).toBe('custom');
    });
  });

  describe('conflict history', () => {
    it('should track conflict history', () => {
      const conflict1: ConflictInfo = {
        type: 'timing',
        path: ['duration'],
        localValue: 1000,
        remoteValue: 2000,
        autoResolvable: true
      };

      const conflict2: ConflictInfo = {
        type: 'property',
        path: ['name'],
        localValue: 'A',
        remoteValue: 'B',
        autoResolvable: false
      };

      resolver.resolveConflict(conflict1);
      resolver.resolveConflict(conflict2);

      const history = resolver.getConflictHistory();
      expect(history).toHaveLength(2);
      expect(history[0]).toEqual(conflict1);
      expect(history[1]).toEqual(conflict2);
    });

    it('should analyze conflict patterns', () => {
      // Add some conflicts
      for (let i = 0; i < 3; i++) {
        resolver.resolveConflict({
          type: 'timing',
          path: ['trial', i.toString(), 'duration'],
          localValue: 1000,
          remoteValue: 2000,
          autoResolvable: true
        });
      }

      resolver.resolveConflict({
        type: 'property',
        path: ['metadata', 'name'],
        localValue: 'A',
        remoteValue: 'B',
        autoResolvable: false
      });

      const analysis = resolver.analyzeConflictPatterns();

      expect(analysis.totalConflicts).toBe(4);
      expect(analysis.byType.timing).toBe(3);
      expect(analysis.byType.property).toBe(1);
      expect(analysis.resolutionSuccess).toBe(3); // 3 auto-resolvable
    });

    it('should clear history', () => {
      resolver.resolveConflict({
        type: 'property',
        path: ['test'],
        localValue: 1,
        remoteValue: 2,
        autoResolvable: false
      });

      expect(resolver.getConflictHistory()).toHaveLength(1);

      resolver.clearHistory();

      expect(resolver.getConflictHistory()).toHaveLength(0);
    });
  });

  describe('suggested resolution', () => {
    it('should use suggested resolution when provided', () => {
      const conflict: ConflictInfo = {
        type: 'property',
        path: ['test'],
        localValue: 'A',
        remoteValue: 'B',
        autoResolvable: false,
        suggestedResolution: 'remote'
      };

      const result = resolver.resolveConflict(conflict);

      expect(result.resolved).toBe(true);
      expect(result.value).toBe('B');
      expect(result.strategy).toBe('suggested-remote');
    });
  });
});

