import { ExperimentCRDT } from './ExperimentCRDT.js';
import type { 
  IEditor, 
  ITimeline, 
  VisualChangeEvent, 
  CodeChangeEvent,
  ForgeScriptAST 
} from './types.js';

/**
 * VisualCodeBinding manages bidirectional synchronization between
 * the visual timeline and code editor through the CRDT.
 */
export class VisualCodeBinding {
  private enabled = true;
  private isUpdating = false;
  private unsubscribes: Array<() => void> = [];

  constructor(
    private crdt: ExperimentCRDT,
    private codeEditor: IEditor,
    private visualTimeline: ITimeline
  ) {
    this.setupVisualToCodeBinding();
    this.setupCodeToVisualBinding();
    this.setupCRDTSync();
  }

  /**
   * Enable or disable the binding
   */
  setEnabled(enabled: boolean): void {
    this.enabled = enabled;
  }

  /**
   * Clean up resources
   */
  destroy(): void {
    this.unsubscribes.forEach(unsub => unsub());
    this.unsubscribes = [];
  }

  /**
   * Set up visual timeline to code editor binding
   */
  private setupVisualToCodeBinding(): void {
    // Handle element movement in timeline
    const handleElementMove = (event: VisualChangeEvent) => {
      if (!this.enabled || this.isUpdating) return;

      this.isUpdating = true;
      try {
        // Update CRDT with visual changes
        this.updateASTFromVisual(event);

        // Regenerate code from updated AST
        this.regenerateCode();
      } finally {
        this.isUpdating = false;
      }
    };

    // Handle element addition
    const handleElementAdd = (event: VisualChangeEvent) => {
      if (!this.enabled || this.isUpdating) return;

      this.isUpdating = true;
      try {
        this.addElementToAST(event);
        this.insertCodeAtPosition(event.position);
      } finally {
        this.isUpdating = false;
      }
    };

    // Handle element deletion
    const handleElementDelete = (event: VisualChangeEvent) => {
      if (!this.enabled || this.isUpdating) return;

      this.isUpdating = true;
      try {
        this.removeElementFromAST(event);
        this.removeCodeForElement(event.elementId);
      } finally {
        this.isUpdating = false;
      }
    };

    // Handle property updates
    const handleElementUpdate = (event: VisualChangeEvent) => {
      if (!this.enabled || this.isUpdating) return;

      this.isUpdating = true;
      try {
        this.updateElementInAST(event);
        this.updateCodeForElement(event.elementId, event.data);
      } finally {
        this.isUpdating = false;
      }
    };

    // Subscribe to timeline events
    this.visualTimeline.on('elementMoved', handleElementMove);
    this.visualTimeline.on('elementAdded', handleElementAdd);
    this.visualTimeline.on('elementDeleted', handleElementDelete);
    this.visualTimeline.on('elementUpdated', handleElementUpdate);

    // Store unsubscribe functions
    this.unsubscribes.push(() => {
      this.visualTimeline.off('elementMoved', handleElementMove);
      this.visualTimeline.off('elementAdded', handleElementAdd);
      this.visualTimeline.off('elementDeleted', handleElementDelete);
      this.visualTimeline.off('elementUpdated', handleElementUpdate);
    });
  }

  /**
   * Set up code editor to visual timeline binding
   */
  private setupCodeToVisualBinding(): void {
    // Handle code changes
    const disposable = this.codeEditor.onDidChangeModelContent((event: any) => {
      if (!this.enabled || this.isUpdating) return;

      this.isUpdating = true;
      try {
        // Parse the code to AST
        const code = this.codeEditor.getValue();
        const ast = this.parseForgeScript(code);

        if (ast) {
          // Update CRDT with parsed AST
          this.crdt.updateFromCode(ast);

          // Update visual timeline
          this.updateTimelineFromAST(ast);
        }
      } catch (error) {
        // Handle parse errors gracefully
        console.error('Failed to parse ForgeScript:', error);
        // Could show error indicators in the UI
      } finally {
        this.isUpdating = false;
      }
    });

    this.unsubscribes.push(() => disposable.dispose());
  }

  /**
   * Set up CRDT change synchronization
   */
  private setupCRDTSync(): void {
    // Subscribe to CRDT changes
    const unsubscribe = this.crdt.onExperimentChange((changes) => {
      if (!this.enabled || this.isUpdating) return;

      this.isUpdating = true;
      try {
        // Update both visual and code based on CRDT changes
        const experiment = this.crdt.getCurrentExperiment();

        // Update visual timeline
        this.syncTimelineWithExperiment(experiment);

        // Update code editor
        this.syncCodeWithExperiment(experiment);
      } finally {
        this.isUpdating = false;
      }
    });

    this.unsubscribes.push(unsubscribe);
  }

  /**
   * Update AST from visual timeline changes
   */
  private updateASTFromVisual(event: VisualChangeEvent): void {
    const path = this.getPathFromVisualEvent(event);
    const value = this.getValueFromVisualEvent(event);

    this.crdt.updateFromVisual(path, value);
  }

  /**
   * Add element to AST from visual timeline
   */
  private addElementToAST(event: VisualChangeEvent): void {
    const path = this.getPathForNewElement(event);
    const element = this.createElementFromVisualEvent(event);

    this.crdt.updateFromVisual(path, element);
  }

  /**
   * Remove element from AST
   */
  private removeElementFromAST(event: VisualChangeEvent): void {
    const path = this.getPathFromVisualEvent(event);

    // Use a special marker for deletion
    this.crdt.updateFromVisual(path, undefined);
  }

  /**
   * Update element in AST
   */
  private updateElementInAST(event: VisualChangeEvent): void {
    const path = [...this.getPathFromVisualEvent(event), ...Object.keys(event.data || {})];
    const values = Object.values(event.data || {});

    // Update each property
    path.forEach((_, index) => {
      if (index < path.length - 1) return;
      const propPath = path.slice(0, index + 1);
      this.crdt.updateFromVisual(propPath, values[index - (path.length - values.length)]);
    });
  }

  /**
   * Regenerate code from current AST
   */
  private regenerateCode(): void {
    const experiment = this.crdt.getCurrentExperiment();
    const code = this.generateForgeScriptCode(experiment);

    // Update editor without triggering change events
    const currentCode = this.codeEditor.getValue();
    if (code !== currentCode) {
      this.isUpdating = true;
      this.codeEditor.setValue(code);
      this.isUpdating = false;
    }
  }

  /**
   * Insert code at specific position
   */
  private insertCodeAtPosition(position?: any): void {
    if (!position) return;

    // This would be more sophisticated in practice
    // For now, just regenerate the entire code
    this.regenerateCode();
  }

  /**
   * Remove code for specific element
   */
  private removeCodeForElement(elementId: string): void {
    // This would remove specific code blocks
    // For now, just regenerate the entire code
    this.regenerateCode();
  }

  /**
   * Update code for specific element
   */
  private updateCodeForElement(elementId: string, data: any): void {
    // This would update specific code blocks
    // For now, just regenerate the entire code
    this.regenerateCode();
  }

  /**
   * Parse ForgeScript code to AST
   */
  private parseForgeScript(code: string): ForgeScriptAST | null {
    // This would use the actual ForgeScript parser
    // For now, return a mock AST
    try {
      return {
        rawCode: code,
        metadata: {},
        timeline: [],
        conditions: {},
        stimuli: []
      };
    } catch (error) {
      return null;
    }
  }

  /**
   * Update visual timeline from AST
   */
  private updateTimelineFromAST(ast: ForgeScriptAST): void {
    // This would update the visual timeline based on the AST
    // Implementation depends on timeline API
  }

  /**
   * Sync timeline with experiment data
   */
  private syncTimelineWithExperiment(experiment: any): void {
    // This would sync the entire timeline with experiment data
    // Implementation depends on timeline API
  }

  /**
   * Sync code editor with experiment data
   */
  private syncCodeWithExperiment(experiment: any): void {
    const code = this.generateForgeScriptCode(experiment);
    const currentCode = this.codeEditor.getValue();

    if (code !== currentCode) {
      this.codeEditor.setValue(code);
    }
  }

  /**
   * Generate ForgeScript code from experiment data
   */
  private generateForgeScriptCode(experiment: any): string {
    // This would use the actual code generator
    // For now, return a simple representation
    return `experiment("${experiment.name || 'Untitled'}")
  .metadata(${JSON.stringify(experiment.metadata || {}, null, 2)})
  .timeline(/* generated timeline code */);`;
  }

  /**
   * Helper methods for path generation
   */
  private getPathFromVisualEvent(event: VisualChangeEvent): string[] {
    const path: string[] = ['timeline'];

    if (event.position?.timeline !== undefined) {
      path.push(event.position.timeline.toString());
    }

    if (event.elementType === 'trial' && event.position?.trial !== undefined) {
      path.push('trials', event.position.trial.toString());
    } else if (event.elementType === 'stimulus' && event.position?.index !== undefined) {
      path.push('stimuli', event.position.index.toString());
    }

    return path;
  }

  private getPathForNewElement(event: VisualChangeEvent): string[] {
    const basePath = this.getPathFromVisualEvent(event);

    // For new elements, we need to specify where to insert
    if (event.elementType === 'trial') {
      return [...basePath.slice(0, -1), 'trials'];
    } else if (event.elementType === 'stimulus') {
      return [...basePath.slice(0, -1), 'stimuli'];
    }

    return basePath;
  }

  private createElementFromVisualEvent(event: VisualChangeEvent): any {
    return {
      id: event.elementId,
      type: event.elementType,
      ...event.data
    };
  }

  private getValueFromVisualEvent(event: VisualChangeEvent): any {
    return event.data;
  }
}

