import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { ExperimentCRDT } from '../src/ExperimentCRDT';
import { VisualCodeBinding } from '../src/VisualCodeBinding';
import type { IEditor, ITimeline, VisualChangeEvent } from '../src/types';

describe('VisualCodeBinding', () => {
  let crdt: ExperimentCRDT;
  let mockEditor: IEditor;
  let mockTimeline: ITimeline;
  let binding: VisualCodeBinding;

  beforeEach(() => {
    // Create CRDT
    crdt = new ExperimentCRDT('test-experiment', {
      enableWebRTC: false,
      enableWebSocket: false,
      enableIndexedDB: false
    });

    // Mock editor
    mockEditor = {
      getValue: vi.fn(() => 'experiment("Test")'),
      setValue: vi.fn(),
      onDidChangeModelContent: vi.fn((listener) => {
        // Store listener for testing
        (mockEditor as any)._contentChangeListener = listener;
        return { dispose: vi.fn() };
      }),
      getModel: vi.fn(),
      executeEdits: vi.fn()
    };

    // Mock timeline
    const listeners: Record<string, Function[]> = {};
    mockTimeline = {
      on: vi.fn((event, handler) => {
        if (!listeners[event]) listeners[event] = [];
        listeners[event].push(handler);
      }),
      off: vi.fn((event, handler) => {
        if (listeners[event]) {
          listeners[event] = listeners[event].filter(h => h !== handler);
        }
      }),
      getElements: vi.fn(() => []),
      updateElement: vi.fn(),
      addElement: vi.fn(() => 'new-element-id'),
      removeElement: vi.fn()
    };

    // Store emit function for testing
    (mockTimeline as any).emit = (event: string, data: any) => {
      if (listeners[event]) {
        listeners[event].forEach(handler => handler(data));
      }
    };

    // Create binding
    binding = new VisualCodeBinding(crdt, mockEditor, mockTimeline);
  });

  afterEach(() => {
    binding?.destroy();
    crdt?.destroy();
  });

  describe('initialization', () => {
    it('should create binding instance', () => {
      expect(binding).toBeDefined();
      expect(mockEditor.onDidChangeModelContent).toHaveBeenCalled();
      expect(mockTimeline.on).toHaveBeenCalledWith('elementMoved', expect.any(Function));
      expect(mockTimeline.on).toHaveBeenCalledWith('elementAdded', expect.any(Function));
      expect(mockTimeline.on).toHaveBeenCalledWith('elementDeleted', expect.any(Function));
      expect(mockTimeline.on).toHaveBeenCalledWith('elementUpdated', expect.any(Function));
    });
  });

  describe('visual to code binding', () => {
    it('should update code when element is moved', () => {
      const event: VisualChangeEvent = {
        type: 'move',
        elementId: 'trial-1',
        elementType: 'trial',
        position: { timeline: 0, trial: 1 },
        oldPosition: { timeline: 0, trial: 0 }
      };

      (mockTimeline as any).emit('elementMoved', event);

      // Should regenerate code
      expect(mockEditor.setValue).toHaveBeenCalled();
    });

    it('should update code when element is added', () => {
      const event: VisualChangeEvent = {
        type: 'add',
        elementId: 'stimulus-1',
        elementType: 'stimulus',
        position: { timeline: 0, trial: 0, index: 0 },
        data: { type: 'text', content: 'Hello' }
      };

      (mockTimeline as any).emit('elementAdded', event);

      expect(mockEditor.setValue).toHaveBeenCalled();
    });

    it('should update code when element is deleted', () => {
      const event: VisualChangeEvent = {
        type: 'delete',
        elementId: 'trial-1',
        elementType: 'trial'
      };

      (mockTimeline as any).emit('elementDeleted', event);

      expect(mockEditor.setValue).toHaveBeenCalled();
    });

    it('should update code when element is updated', () => {
      const event: VisualChangeEvent = {
        type: 'update',
        elementId: 'stimulus-1',
        elementType: 'stimulus',
        data: { duration: 3000 }
      };

      (mockTimeline as any).emit('elementUpdated', event);

      expect(mockEditor.setValue).toHaveBeenCalled();
    });
  });

  describe('code to visual binding', () => {
    it('should update timeline when code changes', () => {
      // Simulate code change
      const changeEvent = {
        changes: [{ text: 'new code' }]
      };

      if ((mockEditor as any)._contentChangeListener) {
        (mockEditor as any)._contentChangeListener(changeEvent);
      }

      // Should update CRDT (we can't easily test timeline updates without more mocking)
      expect(mockEditor.getValue).toHaveBeenCalled();
    });
  });

  describe('enable/disable', () => {
    it('should respect enabled state', () => {
      binding.setEnabled(false);

      // Clear previous calls
      (mockEditor.setValue as any).mockClear();

      // Emit event while disabled
      const event: VisualChangeEvent = {
        type: 'move',
        elementId: 'trial-1',
        elementType: 'trial',
        position: { timeline: 0, trial: 1 }
      };

      (mockTimeline as any).emit('elementMoved', event);

      // Should not update code
      expect(mockEditor.setValue).not.toHaveBeenCalled();

      // Re-enable and test
      binding.setEnabled(true);
      (mockTimeline as any).emit('elementMoved', event);

      // Should update code
      expect(mockEditor.setValue).toHaveBeenCalled();
    });
  });

  describe('cleanup', () => {
    it('should clean up listeners on destroy', () => {
      const offSpy = vi.spyOn(mockTimeline, 'off');

      binding.destroy();

      expect(offSpy).toHaveBeenCalledWith('elementMoved', expect.any(Function));
      expect(offSpy).toHaveBeenCalledWith('elementAdded', expect.any(Function));
      expect(offSpy).toHaveBeenCalledWith('elementDeleted', expect.any(Function));
      expect(offSpy).toHaveBeenCalledWith('elementUpdated', expect.any(Function));
    });
  });
});

