     1→import * as Y from 'yjs';
     2→import { WebrtcProvider } from 'y-webrtc';
     3→import { WebsocketProvider } from 'y-websocket';
     4→import { IndexeddbPersistence } from 'y-indexeddb';
     5→import { Awareness } from 'y-protocols/awareness';
     6→import type { CompiledExperiment, ForgeScriptAST } from '@psyforge/forgescript';
     7→
     8→export interface CRDTOptions {
     9→  websocketUrl?: string;
    10→  enableWebRTC?: boolean;
    11→  enableWebSocket?: boolean;
    12→  enableIndexedDB?: boolean;
    13→  awareness?: boolean;
    14→}
    15→
    16→export interface ExperimentChanges {
    17→  path: string[];
    18→  action: 'add' | 'update' | 'delete';
    19→  value?: any;
    20→  oldValue?: any;
    21→}
    22→
    23→export type ChangeCallback = (changes: ExperimentChanges[]) => void;
    24→export type UnsubscribeFn = () => void;
    25→
    26→/**
    27→ * ExperimentCRDT manages the CRDT document for collaborative experiment editing.
    28→ * It provides synchronization across multiple clients using Y.js.
    29→ */
    30→export class ExperimentCRDT {
    31→  private doc: Y.Doc;
    32→  private experimentMap: Y.Map<any>;
    33→  private providers: Array<WebrtcProvider | WebsocketProvider | IndexeddbPersistence> = [];
    34→  private changeCallbacks: Set<ChangeCallback> = new Set();
    35→  private awareness?: Awareness;
    36→
    37→  constructor(
    38→    private experimentId: string,
    39→    options: CRDTOptions = {}
    40→  ) {
    41→    const {
    42→      websocketUrl = 'wss://sync.psyforge.org',
    43→      enableWebRTC = true,
    44→      enableWebSocket = true,
    45→      enableIndexedDB = true,
    46→      awareness = true
    47→    } = options;
    48→
    49→    // Initialize Y.js document
    50→    this.doc = new Y.Doc();
    51→    this.experimentMap = this.doc.getMap('experiment');
    52→
    53→    // Set up awareness for user presence
    54→    if (awareness) {
    55→      this.awareness = new Awareness(this.doc);
    56→    }
    57→
