import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { ExperimentCRDT } from '../src/ExperimentCRDT';
import { CRDTPerformanceOptimizer } from '../src/CRDTPerformanceOptimizer';

describe('CRDTPerformanceOptimizer', () => {
  let crdt: ExperimentCRDT;
  let optimizer: CRDTPerformanceOptimizer;

  beforeEach(() => {
    vi.useFakeTimers();

    crdt = new ExperimentCRDT('test-experiment', {
      enableWebRTC: false,
      enableWebSocket: false,
      enableIndexedDB: false
    });

    optimizer = new CRDTPerformanceOptimizer(crdt, {
      batchTimeout: 50,
      maxBatchSize: 3
    });
  });

  afterEach(() => {
    vi.useRealTimers();
    optimizer?.destroy();
    crdt?.destroy();
  });

  describe('batch updates', () => {
    it('should batch multiple updates within timeout window', () => {
      const updateSpy = vi.spyOn(crdt, 'updateFromVisual');

      // Add updates (less than max batch size to avoid immediate processing)
      optimizer.batchUpdate(['path1'], 'value1');
      optimizer.batchUpdate(['path2'], 'value2');

      // Updates should not be applied yet
      expect(updateSpy).not.toHaveBeenCalled();

      // Advance time past batch timeout
      vi.advanceTimersByTime(51);

      // All updates should be applied
      expect(updateSpy).toHaveBeenCalledTimes(2);
      expect(updateSpy).toHaveBeenCalledWith(['path1'], 'value1');
      expect(updateSpy).toHaveBeenCalledWith(['path2'], 'value2');
    });

    it('should process batch immediately when max size reached', () => {
      const updateSpy = vi.spyOn(crdt, 'updateFromVisual');

      // Add updates up to max batch size
      optimizer.batchUpdate(['path1'], 'value1');
      optimizer.batchUpdate(['path2'], 'value2');
      optimizer.batchUpdate(['path3'], 'value3');

      // Should process immediately without waiting
      expect(updateSpy).toHaveBeenCalledTimes(3);

      // Add another update
      optimizer.batchUpdate(['path4'], 'value4');

      // Should not be processed yet
      expect(updateSpy).toHaveBeenCalledTimes(3);

      // Advance time
      vi.advanceTimersByTime(51);

      // Now the fourth update should be processed
      expect(updateSpy).toHaveBeenCalledTimes(4);
    });
  });

  describe('performance metrics', () => {
    it('should track metrics', () => {
      const initialMetrics = optimizer.getMetrics();

      expect(initialMetrics).toEqual({
        syncLatency: 0,
        operationCount: 0,
        dataSize: 0,
        compressionRatio: 1,
        batchEfficiency: 1
      });

      // Perform some operations
      optimizer.batchUpdate(['test'], 'value');
      vi.advanceTimersByTime(51);

      const updatedMetrics = optimizer.getMetrics();
      expect(updatedMetrics.operationCount).toBeGreaterThan(0);
    });

    it('should reset metrics', () => {
      // Add some operations
      optimizer.batchUpdate(['test'], 'value');
      vi.advanceTimersByTime(51);

      const metrics = optimizer.getMetrics();
      expect(metrics.operationCount).toBeGreaterThan(0);

      // Reset
      optimizer.resetMetrics();

      const resetMetrics = optimizer.getMetrics();
      expect(resetMetrics.operationCount).toBe(0);
    });
  });

  describe('data optimization', () => {
    it('should optimize large experiment data', () => {
      const largeExperiment = {
        timeline: Array(100).fill(null).map((_, i) => ({
          id: `trial-${i}`,
          type: 'trial',
          duration: 1000,
          stimuli: [{ type: 'text', content: 'Test' }]
        })),
        metadata: {
          name: 'Large Experiment',
          empty: '',
          null: null,
          undefined: undefined
        }
      };

      const optimized = optimizer.optimizeLargeExperiment(largeExperiment);

      // Should remove empty values
      expect(optimized.metadata.empty).toBeUndefined();
      expect(optimized.metadata.null).toBeUndefined();
      expect(optimized.metadata.undefined).toBeUndefined();
    });

    it('should compress repeated trials in timeline', () => {
      // Create optimizer with low compression threshold for testing
      const testOptimizer = new CRDTPerformanceOptimizer(crdt, {
        compressionThreshold: 100 // Lower threshold for testing
      });

      const experiment = {
        timeline: [
          { type: 'trial', duration: 1000, stimulus: 'A' },
          { type: 'trial', duration: 1000, stimulus: 'A' },
          { type: 'trial', duration: 1000, stimulus: 'A' },
          { type: 'trial', duration: 2000, stimulus: 'B' }
        ]
      };

      const optimized = testOptimizer.optimizeLargeExperiment(experiment);

      // Should group similar trials
      expect(optimized.timeline).toHaveLength(2);
      expect(optimized.timeline[0]._repeat).toBe(3);
    });

    it('should not optimize if compression disabled', () => {
      const optimizerNoCompression = new CRDTPerformanceOptimizer(crdt, {
        enableDeltaCompression: false
      });

      const experiment = {
        metadata: { empty: '' }
      };

      const result = optimizerNoCompression.optimizeLargeExperiment(experiment);

      // Should return unchanged
      expect(result).toEqual(experiment);

      optimizerNoCompression.destroy();
    });
  });

  describe('selective sync', () => {
    it('should enable selective sync paths', () => {
      const paths = ['timeline.trials', 'metadata.author'];

      // Should not throw
      expect(() => {
        optimizer.enableSelectiveSync(paths);
      }).not.toThrow();
    });
  });

  describe('memory monitoring', () => {
    it('should monitor memory usage', () => {
      const memoryInfo = optimizer.monitorMemoryUsage();

      expect(memoryInfo).toHaveProperty('used');
      expect(memoryInfo).toHaveProperty('limit');
      expect(memoryInfo).toHaveProperty('percentage');

      // In test environment without performance.memory
      expect(memoryInfo.used).toBe(0);
      expect(memoryInfo.limit).toBe(0);
      expect(memoryInfo.percentage).toBe(0);
    });
  });

  describe('cleanup', () => {
    it('should process remaining batches on destroy', () => {
      const updateSpy = vi.spyOn(crdt, 'updateFromVisual');

      // Add updates but don't wait for timeout
      optimizer.batchUpdate(['path1'], 'value1');
      optimizer.batchUpdate(['path2'], 'value2');

      expect(updateSpy).not.toHaveBeenCalled();

      // Destroy should process remaining
      optimizer.destroy();

      expect(updateSpy).toHaveBeenCalledTimes(2);
    });
  });
});

