    21→  // Format time
    22→  function formatTime(date: Date): string {
    23→    const now = new Date();
    24→    const diff = now.getTime() - date.getTime();
    25→    const minutes = Math.floor(diff / 60000);
    26→    
    27→    if (minutes < 1) return 'Just now';
    28→    if (minutes === 1) return '1 minute ago';
    29→    if (minutes < 60) return `${minutes} minutes ago`;
    30→    
    31→    const hours = Math.floor(minutes / 60);
    32→    if (hours === 1) return '1 hour ago';
    33→    if (hours < 24) return `${hours} hours ago`;
    34→    
    35→    return date.toLocaleDateString();
    36→  }
    37→  
    38→  // Update connection status
    39→  function updateConnectionStatus() {
    40→    connectionStatus = navigator.onLine ? 'online' : 'offline';
    41→  }
    42→  
    43→  // Simulate memory usage
    44→  function updateMemoryUsage() {
    45→    if ('memory' in performance) {
    46→      const memory = (performance as any).memory;
    47→      memoryUsage = Math.round((memory.usedJSHeapSize / memory.jsHeapSizeLimit) * 100);
    48→    } else {
    49→      // Simulate for demo
    50→      memoryUsage = Math.round(Math.random() * 30 + 20);
    51→    }
    52→  }
    53→  
    54→  // Track frame rate
    55→  let frameCount = 0;
    56→  let lastFrameTime = performance.now();
    57→  
    58→  function updateFrameRate() {
    59→    frameCount++;
    60→    const currentTime = performance.now();
    61→    const elapsed = currentTime - lastFrameTime;
    62→    
    63→    if (elapsed >= 1000) {
    64→      frameRate = Math.round((frameCount * 1000) / elapsed);
    65→      frameCount = 0;
    66→      lastFrameTime = currentTime;
    67→    }
    68→    
    69→    requestAnimationFrame(updateFrameRate);
    70→  }
    71→  
    72→  let memoryInterval: number;
    73→  let syncInterval: number;
    74→  
    75→  onMount(() => {
    76→    // Set up event listeners
    77→    window.addEventListener('online', updateConnectionStatus);
    78→    window.addEventListener('offline', updateConnectionStatus);
    79→    
    80→    // Initial checks
    81→    updateConnectionStatus();
    82→    updateMemoryUsage();
    83→    updateFrameRate();
    84→    
    85→    // Set up intervals
    86→    memoryInterval = setInterval(updateMemoryUsage, 5000);
    87→    syncInterval = setInterval(() => {
