import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { get } from 'svelte/store';
import { 
  settings, 
  currentProject, 
  isLoading, 
  error,
  isDarkMode,
  isHighContrast,
  setTheme,
  toggleDarkMode,
  setError
} from './app';
import type { AppSettings } from '$lib/types';

// Mock localStorage
const localStorageMock = {
  getItem: vi.fn(),
  setItem: vi.fn(),
  removeItem: vi.fn(),
  clear: vi.fn()
};

Object.defineProperty(window, 'localStorage', {
  value: localStorageMock
});

describe('app store', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  describe('settings store', () => {
    it('loads default settings when localStorage is empty', () => {
      localStorageMock.getItem.mockReturnValue(null);

      const currentSettings = get(settings);
      expect(currentSettings).toEqual({
        theme: 'light',
        autoSave: true,
        autoSaveInterval: 30000,
        showPerformanceOverlay: false,
        accessibility: {
          reduceMotion: false,
          highContrast: false,
          fontSize: 'medium',
        },
      });
    });

    it('loads settings from localStorage if available', () => {
      const storedSettings = {
        theme: 'dark',
        autoSave: false
      };
      localStorageMock.getItem.mockReturnValue(JSON.stringify(storedSettings));

      // Re-import to trigger loading
      vi.resetModules();
      const { settings: reloadedSettings } = require('./app');

      const currentSettings = get(reloadedSettings);
      expect(currentSettings.theme).toBe('dark');
      expect(currentSettings.autoSave).toBe(false);
    });

    it('handles invalid JSON in localStorage', () => {
      localStorageMock.getItem.mockReturnValue('invalid json');

      // Re-import to trigger loading
      vi.resetModules();
      const { settings: reloadedSettings } = require('./app');

      const currentSettings = get(reloadedSettings);
      expect(currentSettings.theme).toBe('light'); // Should use defaults
    });

    it('persists settings to localStorage on update', () => {
      settings.update(s => ({ ...s, theme: 'dark' }));

      expect(localStorageMock.setItem).toHaveBeenCalledWith(
        'psyforge-settings',
        expect.stringContaining('"theme":"dark"')
      );
    });
  });

  describe('currentProject store', () => {
    it('initializes as null', () => {
      expect(get(currentProject)).toBeNull();
    });

    it('can be updated with a project', () => {
      const project = {
        id: '123',
        name: 'Test Project',
        experiments: [],
        createdAt: new Date(),
        updatedAt: new Date(),
        collaborators: [],
        version: '1.0.0'
      };

      currentProject.set(project);
      expect(get(currentProject)).toEqual(project);
    });
  });

  describe('loading and error states', () => {
    it('initializes loading as false', () => {
      expect(get(isLoading)).toBe(false);
    });

    it('can update loading state', () => {
      isLoading.set(true);
      expect(get(isLoading)).toBe(true);
    });

    it('initializes error as null', () => {
      expect(get(error)).toBeNull();
    });

    it('auto-clears error after 5 seconds', () => {
      setError('Test error');
      expect(get(error)).toBe('Test error');

      vi.advanceTimersByTime(5000);
      expect(get(error)).toBeNull();
    });

    it('does not clear error if it changed', () => {
      setError('First error');
      setError('Second error');

      vi.advanceTimersByTime(5000);
      expect(get(error)).toBe('Second error'); // First timeout shouldn't clear second error
    });
  });

  describe('derived stores', () => {
    it('isDarkMode reflects dark theme', () => {
      settings.set({ ...get(settings), theme: 'light' });
      expect(get(isDarkMode)).toBe(false);

      settings.set({ ...get(settings), theme: 'dark' });
      expect(get(isDarkMode)).toBe(true);
    });

    it('isHighContrast reflects high-contrast theme or setting', () => {
      settings.set({ ...get(settings), theme: 'light', accessibility: { ...get(settings).accessibility, highContrast: false } });
      expect(get(isHighContrast)).toBe(false);

      settings.set({ ...get(settings), theme: 'high-contrast' });
      expect(get(isHighContrast)).toBe(true);

      settings.set({ ...get(settings), theme: 'light', accessibility: { ...get(settings).accessibility, highContrast: true } });
      expect(get(isHighContrast)).toBe(true);
    });
  });

  describe('utility functions', () => {
    it('setTheme updates theme', () => {
      setTheme('dark');
      expect(get(settings).theme).toBe('dark');

      setTheme('high-contrast');
      expect(get(settings).theme).toBe('high-contrast');
    });

    it('toggleDarkMode switches between light and dark', () => {
      settings.set({ ...get(settings), theme: 'light' });
      toggleDarkMode();
      expect(get(settings).theme).toBe('dark');

      toggleDarkMode();
      expect(get(settings).theme).toBe('light');
    });

    it('setError sets and auto-clears error', () => {
      setError('Test error');
      expect(get(error)).toBe('Test error');

      vi.advanceTimersByTime(5000);
      expect(get(error)).toBeNull();
    });

    it('setError with null clears immediately', () => {
      error.set('Existing error');
      setError(null);
      expect(get(error)).toBeNull();
    });
  });
});

