     1→import type { ConflictInfo } from './types.js';
     2→
     3→export interface ConflictResolutionStrategy {
     4→  type: 'automatic' | 'manual' | 'custom';
     5→  preference?: 'local' | 'remote' | 'newer' | 'merge';
     6→  customResolver?: (conflict: ConflictInfo) => any;
     7→}
     8→
     9→export interface ConflictResolutionResult {
    10→  resolved: boolean;
    11→  value: any;
    12→  strategy: string;
    13→  confidence: number;
    14→}
    15→
    16→/**
    17→ * ConflictResolution handles merge conflicts in collaborative editing
    18→ */
    19→export class ConflictResolution {
    20→  private strategies: Map<string, ConflictResolutionStrategy> = new Map();
    21→  private conflictHistory: ConflictInfo[] = [];
    22→
    23→  constructor() {
    24→    this.setupDefaultStrategies();
    25→  }
    26→
    27→  /**
    28→   * Register a conflict resolution strategy for a specific path pattern
    29→   */
    30→  registerStrategy(pathPattern: string, strategy: ConflictResolutionStrategy): void {
    31→    this.strategies.set(pathPattern, strategy);
    32→  }
    33→
    34→  /**
    35→   * Resolve a conflict based on registered strategies
    36→   */
    37→  resolveConflict(conflict: ConflictInfo): ConflictResolutionResult {
    38→    // Track conflict for analysis
    39→    this.conflictHistory.push(conflict);
    40→
    41→    // Try automatic resolution first
    42→    if (conflict.autoResolvable) {
    43→      const autoResult = this.tryAutomaticResolution(conflict);
    44→      if (autoResult.resolved) {
    45→        return autoResult;
    46→      }
    47→    }
    48→
    49→    // Find matching strategy
    50→    const strategy = this.findMatchingStrategy(conflict.path);
    51→    
    52→    if (strategy) {
    53→      return this.applyStrategy(conflict, strategy);
    54→    }
    55→
    56→    // Default resolution
    57→    return this.defaultResolution(conflict);
    58→  }
    59→
    60→  /**
    61→   * Get conflict history for analysis
    62→   */
    63→  getConflictHistory(): ConflictInfo[] {
    64→    return [...this.conflictHistory];
    65→  }
    66→
    67→  /**
    68→   * Clear conflict history
    69→   */
    70→  clearHistory(): void {
    71→    this.conflictHistory = [];
    72→  }
    73→
    74→  /**
    75→   * Analyze conflict patterns
    76→   */
    77→  analyzeConflictPatterns(): {
    78→    totalConflicts: number;
    79→    byType: Record<string, number>;
    80→    byPath: Record<string, number>;
    81→    resolutionSuccess: number;
    82→  } {
    83→    const analysis = {
    84→      totalConflicts: this.conflictHistory.length,
    85→      byType: {} as Record<string, number>,
    86→      byPath: {} as Record<string, number>,
    87→      resolutionSuccess: 0
    88→    };
    89→
    90→    this.conflictHistory.forEach(conflict => {
    91→      // Count by type
    92→      analysis.byType[conflict.type] = (analysis.byType[conflict.type] || 0) + 1;
    93→
    94→      // Count by path
    95→      const pathKey = conflict.path.join('.');
    96→      analysis.byPath[pathKey] = (analysis.byPath[pathKey] || 0) + 1;
    97→
    98→      // Count successful resolutions
    99→      if (conflict.autoResolvable) {
   100→        analysis.resolutionSuccess++;
   101→      }
   102→    });
   103→
   104→    return analysis;
   105→  }
   106→
   107→  /**
   108→   * Set up default resolution strategies
   109→   */
   110→  private setupDefaultStrategies(): void {
   111→    // Timing conflicts - prefer more conservative (longer) timing
   112→    this.registerStrategy('*.duration', {
   113→      type: 'automatic',
   114→      preference: 'merge',
   115→      customResolver: (conflict) => {
   116→        const local = parseFloat(conflict.localValue);
   117→        const remote = parseFloat(conflict.remoteValue);
   118→        return Math.max(local, remote);
   119→      }
   120→    });
   121→
   122→    // Position conflicts - prefer local user's positioning
   123→    this.registerStrategy('*.position.*', {
   124→      type: 'automatic',
   125→      preference: 'local'
   126→    });
   127→
   128→    // Metadata conflicts - merge objects
   129→    this.registerStrategy('metadata.*', {
   130→      type: 'automatic',
   131→      preference: 'merge',
   132→      customResolver: (conflict) => {
   133→        if (typeof conflict.localValue === 'object' && typeof conflict.remoteValue === 'object') {
   134→          return { ...conflict.remoteValue, ...conflict.localValue };
   135→        }
   136→        return conflict.localValue;
   137→      }
   138→    });
   139→
   140→    // Array order conflicts - require manual resolution
   141→    this.registerStrategy('timeline.*.order', {
   142→      type: 'manual'
   143→    });
   144→  }
   145→
   146→  /**
   147→   * Try automatic resolution for simple conflicts
   148→   */
   149→  private tryAutomaticResolution(conflict: ConflictInfo): ConflictResolutionResult {
   150→    // Numeric values - average or max
   151→    if (typeof conflict.localValue === 'number' && typeof conflict.remoteValue === 'number') {
   152→      if (conflict.type === 'timing') {
   153→        // For timing, use maximum to be safe
   154→        return {
   155→          resolved: true,
   156→          value: Math.max(conflict.localValue, conflict.remoteValue),
   157→          strategy: 'max-value',
   158→          confidence: 0.9
   159→        };
   160→      } else {
   161→        // For other numbers, average
   162→        return {
   163→          resolved: true,
   164→          value: (conflict.localValue + conflict.remoteValue) / 2,
   165→          strategy: 'average',
   166→          confidence: 0.7
   167→        };
   168→      }
   169→    }
   170→
   171→    // String values - check if one is empty
   172→    if (typeof conflict.localValue === 'string' && typeof conflict.remoteValue === 'string') {
   173→      if (!conflict.localValue.trim()) {
   174→        return {
   175→          resolved: true,
   176→          value: conflict.remoteValue,
   177→          strategy: 'non-empty',
   178→          confidence: 0.8
   179→        };
   180→      }
   181→      if (!conflict.remoteValue.trim()) {
   182→        return {
   183→          resolved: true,
   184→          value: conflict.localValue,
   185→          strategy: 'non-empty',
   186→          confidence: 0.8
   187→        };
   188→      }
   189→    }
   190→
   191→    // Boolean values - require manual resolution
   192→    if (typeof conflict.localValue === 'boolean' && typeof conflict.remoteValue === 'boolean') {
   193→      if (conflict.localValue !== conflict.remoteValue) {
   194→        return {
   195→          resolved: false,
   196→          value: conflict.localValue,
   197→          strategy: 'manual-required',
   198→          confidence: 0
   199→        };
   200→      }
   201→    }
   202→
   203→    return {
   204→      resolved: false,
   205→      value: conflict.localValue,
   206→      strategy: 'no-auto-resolution',
   207→      confidence: 0
   208→    };
   209→  }
   210→
   211→  /**
   212→   * Find matching strategy for a path
   213→   */
   214→  private findMatchingStrategy(path: string[]): ConflictResolutionStrategy | null {
   215→    const pathString = path.join('.');
   216→    
   217→    // Check exact match first
   218→    if (this.strategies.has(pathString)) {
   219→      return this.strategies.get(pathString)!;
   220→    }
   221→
   222→    // Check pattern matches
   223→    for (const [pattern, strategy] of this.strategies) {
   224→      if (this.matchesPattern(pathString, pattern)) {
   225→        return strategy;
   226→      }
   227→    }
   228→
   229→    return null;
   230→  }
   231→
   232→  /**
   233→   * Check if a path matches a pattern
   234→   */
   235→  private matchesPattern(path: string, pattern: string): boolean {
   236→    // Convert pattern to regex
   237→    // First escape dots, then handle ** for any depth, then * for single segment
   238→    const regexPattern = pattern
   239→      .replace(/\./g, '\\.')
   240→      .replace(/\*\*/g, '__DOUBLE_STAR__')
   241→      .replace(/\*/g, '[^.]+')
   242→      .replace(/__DOUBLE_STAR__/g, '.*');
   243→    
   244→    const regex = new RegExp(`^${regexPattern}$`);
   245→    return regex.test(path);
   246→  }
   247→
   248→  /**
   249→   * Apply a resolution strategy
   250→   */
   251→  private applyStrategy(conflict: ConflictInfo, strategy: ConflictResolutionStrategy): ConflictResolutionResult {
   252→    if (strategy.type === 'manual') {
   253→      return {
   254→        resolved: false,
   255→        value: conflict.localValue,
   256→        strategy: 'manual',
   257→        confidence: 0
   258→      };
   259→    }
   260→
   261→    if (strategy.customResolver) {
   262→      try {
   263→        const value = strategy.customResolver(conflict);
   264→        return {
   265→          resolved: true,
   266→          value,
   267→          strategy: 'custom',
   268→          confidence: 0.8
   269→        };
   270→      } catch (error) {
   271→        console.error('Custom resolver failed:', error);
   272→      }
   273→    }
   274→
   275→    // Apply preference-based resolution
   276→    switch (strategy.preference) {
   277→      case 'local':
   278→        return {
   279→          resolved: true,
   280→          value: conflict.localValue,
   281→          strategy: 'prefer-local',
   282→          confidence: 0.7
   283→        };
   284→      
   285→      case 'remote':
   286→        return {
   287→          resolved: true,
   288→          value: conflict.remoteValue,
   289→          strategy: 'prefer-remote',
   290→          confidence: 0.7
   291→        };
   292→      
   293→      case 'newer':
   294→        // This would require timestamp information
   295→        return {
   296→          resolved: true,
   297→          value: conflict.localValue, // Default to local without timestamps
   298→          strategy: 'prefer-newer',
   299→          confidence: 0.5
   300→        };
   301→      
   302→      case 'merge':
   303→        if (typeof conflict.localValue === 'object' && typeof conflict.remoteValue === 'object') {
   304→          return {
   305→            resolved: true,
   306→            value: this.mergeObjects(conflict.localValue, conflict.remoteValue),
   307→            strategy: 'merge',
   308→            confidence: 0.8
   309→          };
   310→        }
   311→        break;
   312→    }
   313→
   314→    return this.defaultResolution(conflict);
   315→  }
   316→
   317→  /**
   318→   * Default resolution when no strategy matches
   319→   */
   320→  private defaultResolution(conflict: ConflictInfo): ConflictResolutionResult {
   321→    // Check if this is a boolean conflict that differs
   322→    if (typeof conflict.localValue === 'boolean' && 
   323→        typeof conflict.remoteValue === 'boolean' &&
   324→        conflict.localValue !== conflict.remoteValue) {
   325→      return {
   326→        resolved: false,
   327→        value: conflict.localValue,
   328→        strategy: 'manual-required',
   329→        confidence: 0
   330→      };
   331→    }
   332→
   333→    if (conflict.suggestedResolution) {
   334→      const value = conflict.suggestedResolution === 'local' 
   335→        ? conflict.localValue 
   336→        : conflict.suggestedResolution === 'remote'
   337→        ? conflict.remoteValue
   338→        : this.mergeValues(conflict.localValue, conflict.remoteValue);
   339→
   340→      return {
   341→        resolved: true,
   342→        value,
   343→        strategy: `suggested-${conflict.suggestedResolution}`,
   344→        confidence: 0.6
   345→      };
   346→    }
   347→
   348→    // Default to local value
