   312→   */
   313→  private hashStimulus(stimulus: any): string {
   314→    // Simple hash based on stimulus properties
   315→    return JSON.stringify({
   316→      type: stimulus.type,
   317→      content: stimulus.content,
   318→      duration: stimulus.duration,
   319→      position: stimulus.position
   320→    });
   321→  }
   322→
   323→  /**
   324→   * Update performance metrics
   325→   */
   326→  private updateMetrics(latency: number, operationCount: number): void {
   327→    // Update rolling average for latency
   328→    this.metrics.syncLatency = (this.metrics.syncLatency * 0.9) + (latency * 0.1);
   329→    
   330→    // Update operation count
   331→    this.metrics.operationCount += operationCount;
   332→    
   333→    // Calculate batch efficiency
   334→    this.metrics.batchEfficiency = operationCount > 1 
   335→      ? operationCount / (latency / 10) // Operations per 10ms
   336→      : 1;
   337→  }
   338→
   339→  /**
   340→   * Monitor memory usage during editing sessions
   341→   */
   342→  monitorMemoryUsage(): { used: number; limit: number; percentage: number } {
   343→    if ('memory' in performance) {
   344→      const memory = (performance as any).memory;
   345→      return {
   346→        used: memory.usedJSHeapSize,
   347→        limit: memory.jsHeapSizeLimit,
   348→        percentage: (memory.usedJSHeapSize / memory.jsHeapSizeLimit) * 100
   349→      };
   350→    }
   351→    
   352→    // Fallback for browsers without memory API
   353→    return {
   354→      used: 0,
   355→      limit: 0,
   356→      percentage: 0
   357→    };
   358→  }
   359→}

