import * as Y from 'yjs';
import { ExperimentCRDT } from './ExperimentCRDT.js';

export interface OptimizationOptions {
  batchTimeout?: number;
  maxBatchSize?: number;
  compressionThreshold?: number;
  selectiveSyncPaths?: string[];
  enableDeltaCompression?: boolean;
}

export interface PerformanceMetrics {
  syncLatency: number;
  operationCount: number;
  dataSize: number;
  compressionRatio: number;
  batchEfficiency: number;
}

/**
 * CRDTPerformanceOptimizer provides performance optimizations
 * for CRDT operations on large experiments.
 */
export class CRDTPerformanceOptimizer {
  private batchedOperations: Array<{ path: string[]; value: any }> = [];
  private batchTimer: NodeJS.Timeout | null = null;
  private metrics: PerformanceMetrics = {
    syncLatency: 0,
    operationCount: 0,
    dataSize: 0,
    compressionRatio: 1,
    batchEfficiency: 1
  };

  private operationStartTimes: Map<string, number> = new Map();

  constructor(
    private crdt: ExperimentCRDT,
    private options: OptimizationOptions = {}
  ) {
    this.options = {
      batchTimeout: 50, // 50ms default batching window
      maxBatchSize: 100,
      compressionThreshold: 1024, // 1KB
      enableDeltaCompression: true,
      ...options
    };
  }

  /**
   * Batch update operations for better performance
   */
  batchUpdate(path: string[], value: any): void {
    this.batchedOperations.push({ path, value });

    // Clear existing timer
    if (this.batchTimer) {
      clearTimeout(this.batchTimer);
    }

    // Process batch if it's getting too large
    if (this.batchedOperations.length >= (this.options.maxBatchSize || 100)) {
      this.processBatch();
      return;
    }

    // Set new timer
    this.batchTimer = setTimeout(() => {
      this.processBatch();
    }, this.options.batchTimeout || 50);
  }

  /**
   * Process batched operations
   */
  private processBatch(): void {
    if (this.batchedOperations.length === 0) return;

    const startTime = performance.now();
    const operationId = `batch-${Date.now()}`;
    this.operationStartTimes.set(operationId, startTime);

    // Get Y.Doc for transaction
    const doc = this.crdt.getDoc();

    // Apply all operations in a single transaction
    doc.transact(() => {
      this.batchedOperations.forEach(({ path, value }) => {
        this.crdt.updateFromVisual(path, value);
      });
    }, 'batch-update');

    // Update metrics
    const endTime = performance.now();
    const latency = endTime - startTime;
    this.updateMetrics(latency, this.batchedOperations.length);

    // Clear batch
    this.batchedOperations = [];
    this.batchTimer = null;

    // Clean up timing map
    this.operationStartTimes.delete(operationId);
  }

  /**
   * Optimize large experiment data structures
   */
  optimizeLargeExperiment(experiment: any): any {
    if (!this.options.enableDeltaCompression) {
      return experiment;
    }

    const dataSize = JSON.stringify(experiment).length;

    if (dataSize < (this.options.compressionThreshold || 1024)) {
      return experiment;
    }

    // Apply optimizations
    const optimized = this.compressExperimentData(experiment);

    // Update compression metrics
    const compressedSize = JSON.stringify(optimized).length;
    this.metrics.compressionRatio = dataSize / compressedSize;

    return optimized;
  }

  /**
   * Enable selective synchronization for large experiment trees
   */
  enableSelectiveSync(paths: string[]): void {
    this.options.selectiveSyncPaths = paths;

    // This would integrate with Y.js subdocuments or custom sync logic
    // For now, we'll store the paths for future use
  }

  /**
   * Get current performance metrics
   */
  getMetrics(): PerformanceMetrics {
    return { ...this.metrics };
  }

  /**
   * Reset performance metrics
   */
  resetMetrics(): void {
    this.metrics = {
      syncLatency: 0,
      operationCount: 0,
      dataSize: 0,
      compressionRatio: 1,
      batchEfficiency: 1
    };
  }

  /**
   * Clean up resources
   */
  destroy(): void {
    if (this.batchTimer) {
      clearTimeout(this.batchTimer);
      this.processBatch(); // Process any remaining operations
    }

    this.operationStartTimes.clear();
  }

  /**
   * Compress experiment data for efficient transmission
   */
  private compressExperimentData(experiment: any): any {
    // Remove redundant data
    const compressed = this.removeRedundantData(experiment);

    // Compress large arrays
    if (compressed.timeline && Array.isArray(compressed.timeline)) {
      compressed.timeline = this.compressTimeline(compressed.timeline);
    }

    // Compress stimuli data
    if (compressed.stimuli && Array.isArray(compressed.stimuli)) {
      compressed.stimuli = this.compressStimuli(compressed.stimuli);
    }

    return compressed;
  }

  /**
   * Remove redundant data from experiment
   */
  private removeRedundantData(data: any): any {
    if (Array.isArray(data)) {
      return data.map(item => this.removeRedundantData(item));
    }

    if (typeof data === 'object' && data !== null) {
      const cleaned: any = {};

      for (const [key, value] of Object.entries(data)) {
        // Skip null, undefined, or empty values
        if (value === null || value === undefined || 
            (typeof value === 'string' && value.trim() === '') ||
            (Array.isArray(value) && value.length === 0)) {
          continue;
        }

        cleaned[key] = this.removeRedundantData(value);
      }

      return cleaned;
    }

    return data;
  }

  /**
   * Compress timeline data
   */
  private compressTimeline(timeline: any[]): any[] {
    // Group similar trials
    const compressed: any[] = [];
    let currentGroup: any = null;
    let groupCount = 0;

    timeline.forEach(trial => {
      if (this.canGroupTrial(currentGroup, trial)) {
        groupCount++;
      } else {
        if (currentGroup && groupCount > 1) {
          compressed.push({
            ...currentGroup,
            _repeat: groupCount
          });
        } else if (currentGroup) {
          compressed.push(currentGroup);
        }

        currentGroup = { ...trial };
        groupCount = 1;
      }
    });

    // Add last group
    if (currentGroup && groupCount > 1) {
      compressed.push({
        ...currentGroup,
        _repeat: groupCount
      });
    } else if (currentGroup) {
      compressed.push(currentGroup);
    }

    return compressed;
  }

  /**
   * Check if trials can be grouped
   */
  private canGroupTrial(group: any, trial: any): boolean {
    if (!group || !trial) return false;

    // Compare trial properties (excluding ID and specific values)
    const groupKeys = Object.keys(group).filter(k => k !== 'id' && k !== '_repeat');
    const trialKeys = Object.keys(trial).filter(k => k !== 'id');

    if (groupKeys.length !== trialKeys.length) return false;

    return groupKeys.every(key => {
      if (key === 'stimuli' || key === 'responses') {
        // For arrays, check structure similarity
        return JSON.stringify(group[key]) === JSON.stringify(trial[key]);
      }
      return group[key] === trial[key];
    });
  }

  /**
   * Compress stimuli data
   */
  private compressStimuli(stimuli: any[]): any[] {
    // De-duplicate identical stimuli
    const uniqueStimuli: any[] = [];
    const stimulusMap = new Map<string, number>();

    stimuli.forEach(stimulus => {
      const hash = this.hashStimulus(stimulus);

      if (!stimulusMap.has(hash)) {
        stimulusMap.set(hash, uniqueStimuli.length);
        uniqueStimuli.push(stimulus);
      }
    });

    // If significant compression achieved, return reference array
    if (uniqueStimuli.length < stimuli.length * 0.8) {
      return {
        _type: 'compressed',
        unique: uniqueStimuli,
        indices: stimuli.map(s => stimulusMap.get(this.hashStimulus(s))!)
      } as any;
    }

    return stimuli;
  }

  /**
   * Create hash for stimulus deduplication
   */
  private hashStimulus(stimulus: any): string {
    // Simple hash based on stimulus properties
    return JSON.stringify({
      type: stimulus.type,
      content: stimulus.content,
      duration: stimulus.duration,
      position: stimulus.position
    });
  }

  /**
   * Update performance metrics
   */
  private updateMetrics(latency: number, operationCount: number): void {
    // Update rolling average for latency
    this.metrics.syncLatency = (this.metrics.syncLatency * 0.9) + (latency * 0.1);

    // Update operation count
    this.metrics.operationCount += operationCount;

    // Calculate batch efficiency
    this.metrics.batchEfficiency = operationCount > 1 
      ? operationCount / (latency / 10) // Operations per 10ms
      : 1;
  }

  /**
   * Monitor memory usage during editing sessions
   */
  monitorMemoryUsage(): { used: number; limit: number; percentage: number } {
    if ('memory' in performance) {
      const memory = (performance as any).memory;
      return {
        used: memory.usedJSHeapSize,
        limit: memory.jsHeapSizeLimit,
        percentage: (memory.usedJSHeapSize / memory.jsHeapSizeLimit) * 100
      };
    }

    // Fallback for browsers without memory API
    return {
      used: 0,
      limit: 0,
      percentage: 0
    };
  }
}

