   399→   */
   400→  private generateSessionId(): string {
   401→    return `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
   402→  }
   403→
   404→  /**
   405→   * Format bytes for display
   406→   */
   407→  private formatBytes(bytes: number): string {
   408→    if (bytes < 1024) return `${bytes} B`;
   409→    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
   410→    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
   411→  }
   412→
   413→  /**
   414→   * Calculate reliability percentage
   415→   */
   416→  private calculateReliability(): number {
   417→    const total = this.sessionMetrics.changeCount + this.sessionMetrics.errorCount;
   418→    if (total === 0) return 100;
   419→    
   420→    return Math.round((this.sessionMetrics.changeCount / total) * 100);
   421→  }
   422→
   423→  /**
   424→   * Calculate conflict resolution rate
   425→   */
   426→  private calculateConflictResolutionRate(): number {
   427→    if (this.sessionMetrics.conflictCount === 0) return 100;
   428→    
   429→    // Assume conflicts are resolved if no errors
   430→    const resolved = this.sessionMetrics.conflictCount - 
   431→                    (this.sessionMetrics.errorCount * 0.1); // Estimate
   432→    
   433→    return Math.round((resolved / this.sessionMetrics.conflictCount) * 100);
   434→  }
   435→
   436→  /**
   437→   * Calculate overall performance score
   438→   */
   439→  private calculatePerformanceScore(): number {
   440→    let score = 100;
   441→    
   442→    // Deduct for high latency
   443→    if (this.sessionMetrics.averageSyncLatency > 100) {
   444→      score -= Math.min(20, (this.sessionMetrics.averageSyncLatency - 100) / 10);
   445→    }
   446→    
   447→    // Deduct for conflicts
   448→    if (this.metrics.conflictRate > 1) {
   449→      score -= Math.min(20, this.metrics.conflictRate * 5);
   450→    }
   451→    
   452→    // Deduct for errors
   453→    if (this.sessionMetrics.errorCount > 0) {
   454→      score -= Math.min(30, this.sessionMetrics.errorCount * 5);
   455→    }
   456→    
   457→    return Math.max(0, Math.round(score));
   458→  }
   459→}

