import type { CollaborationMetrics } from './types.js';

export interface TelemetryEvent {
  timestamp: number;
  type: string;
  data: Record<string, any>;
  userId?: string;
  sessionId: string;
}

export interface TelemetryOptions {
  enabled?: boolean;
  sampleRate?: number;
  batchSize?: number;
  flushInterval?: number;
  endpoint?: string;
  privacyMode?: boolean;
}

export interface SessionMetrics {
  sessionId: string;
  startTime: number;
  duration: number;
  userCount: number;
  changeCount: number;
  conflictCount: number;
  averageSyncLatency: number;
  peakSyncLatency: number;
  dataTransferred: number;
  errorCount: number;
}

/**
 * CollaborationTelemetry provides comprehensive telemetry for monitoring
 * collaboration performance and reliability.
 */
export class CollaborationTelemetry {
  private events: TelemetryEvent[] = [];
  private metrics: CollaborationMetrics = {
    syncLatency: 0,
    changeRate: 0,
    conflictRate: 0,
    activeUsers: 0,
    dataSize: 0
  };
  private sessionMetrics: SessionMetrics;
  private flushTimer: NodeJS.Timeout | null = null;
  private changeTimestamps: number[] = [];
  private conflictTimestamps: number[] = [];
  private latencyMeasurements: number[] = [];

  constructor(
    private options: TelemetryOptions = {}
  ) {
    this.options = {
      enabled: true,
      sampleRate: 1.0, // 100% sampling by default
      batchSize: 100,
      flushInterval: 30000, // 30 seconds
      privacyMode: false,
      ...options
    };

    this.sessionMetrics = {
      sessionId: this.generateSessionId(),
      startTime: Date.now(),
      duration: 0,
      userCount: 0,
      changeCount: 0,
      conflictCount: 0,
      averageSyncLatency: 0,
      peakSyncLatency: 0,
      dataTransferred: 0,
      errorCount: 0
    };

    if (this.options.enabled) {
      this.startPeriodicFlush();
    }
  }

  /**
   * Track a telemetry event
   */
  trackEvent(type: string, data: Record<string, any>, userId?: string): void {
    if (!this.options.enabled || !this.shouldSample()) {
      return;
    }

    const event: TelemetryEvent = {
      timestamp: Date.now(),
      type,
      data: this.sanitizeData(data),
      userId: this.options.privacyMode ? undefined : userId,
      sessionId: this.sessionMetrics.sessionId
    };

    this.events.push(event);
    this.updateMetricsFromEvent(event);

    // Flush if batch size reached
    if (this.events.length >= (this.options.batchSize || 100)) {
      this.flush();
    }
  }

  /**
   * Track sync latency
   */
  trackSyncLatency(latency: number): void {
    if (!this.options.enabled) return;

    this.latencyMeasurements.push(latency);

    // Keep only last 100 measurements
    if (this.latencyMeasurements.length > 100) {
      this.latencyMeasurements.shift();
    }

    // Update metrics
    this.metrics.syncLatency = this.calculateAverageLatency();
    this.sessionMetrics.averageSyncLatency = this.metrics.syncLatency;
    this.sessionMetrics.peakSyncLatency = Math.max(
      this.sessionMetrics.peakSyncLatency,
      latency
    );

    this.trackEvent('sync.latency', { latency });
  }

  /**
   * Track a change event
   */
  trackChange(changeData: Record<string, any>): void {
    if (!this.options.enabled) return;

    this.changeTimestamps.push(Date.now());
    this.sessionMetrics.changeCount++;

    // Calculate change rate (changes per minute)
    this.updateChangeRate();

    this.trackEvent('change', changeData);
  }

  /**
   * Track a conflict
   */
  trackConflict(conflictData: Record<string, any>): void {
    if (!this.options.enabled) return;

    this.conflictTimestamps.push(Date.now());
    this.sessionMetrics.conflictCount++;

    // Calculate conflict rate
    this.updateConflictRate();

    this.trackEvent('conflict', conflictData);
  }

  /**
   * Track an error
   */
  trackError(error: Error, context?: Record<string, any>): void {
    if (!this.options.enabled) return;

    this.sessionMetrics.errorCount++;

    this.trackEvent('error', {
      message: error.message,
      stack: this.options.privacyMode ? undefined : error.stack,
      ...context
    });
  }

  /**
   * Track data transfer
   */
  trackDataTransfer(bytes: number, direction: 'sent' | 'received'): void {
    if (!this.options.enabled) return;

    this.sessionMetrics.dataTransferred += bytes;
    this.metrics.dataSize = this.sessionMetrics.dataTransferred;

    this.trackEvent('data.transfer', { bytes, direction });
  }

  /**
   * Update active user count
   */
  updateActiveUsers(count: number): void {
    if (!this.options.enabled) return;

    this.metrics.activeUsers = count;
    this.sessionMetrics.userCount = Math.max(this.sessionMetrics.userCount, count);

    this.trackEvent('users.active', { count });
  }

  /**
   * Get current metrics
   */
  getMetrics(): CollaborationMetrics {
    return { ...this.metrics };
  }

  /**
   * Get session metrics
   */
  getSessionMetrics(): SessionMetrics {
    return {
      ...this.sessionMetrics,
      duration: Date.now() - this.sessionMetrics.startTime
    };
  }

  /**
   * Flush pending events
   */
  async flush(): Promise<void> {
    if (this.events.length === 0 || !this.options.endpoint) {
      return;
    }

    const eventsToSend = [...this.events];
    this.events = [];

    try {
      await this.sendTelemetry(eventsToSend);
    } catch (error) {
      console.error('Failed to send telemetry:', error);

      // Put events back if send failed
      this.events.unshift(...eventsToSend);
    }
  }

  /**
   * Clean up resources
   */
  destroy(): void {
    if (this.flushTimer) {
      clearInterval(this.flushTimer);
    }

    // Final flush
    this.flush().catch(console.error);
  }

  /**
   * Generate performance report
   */
  generateReport(): string {
    const session = this.getSessionMetrics();
    const metrics = this.getMetrics();

    return `
Collaboration Performance Report
================================

Session ID: ${session.sessionId}
Duration: ${Math.round(session.duration / 1000)}s
Active Users (Peak): ${session.userCount}

Performance Metrics:
- Average Sync Latency: ${Math.round(session.averageSyncLatency)}ms
- Peak Sync Latency: ${Math.round(session.peakSyncLatency)}ms
- Change Rate: ${metrics.changeRate.toFixed(1)} changes/min
- Conflict Rate: ${metrics.conflictRate.toFixed(2)} conflicts/min
- Data Transferred: ${this.formatBytes(session.dataTransferred)}
- Total Changes: ${session.changeCount}
- Total Conflicts: ${session.conflictCount}
- Errors: ${session.errorCount}

Quality Indicators:
- Sync Reliability: ${this.calculateReliability()}%
- Conflict Resolution Rate: ${this.calculateConflictResolutionRate()}%
- Performance Score: ${this.calculatePerformanceScore()}/100
`;
  }

  /**
   * Start periodic flush
   */
  private startPeriodicFlush(): void {
    if (this.flushTimer) {
      clearInterval(this.flushTimer);
    }

    this.flushTimer = setInterval(() => {
      this.flush().catch(console.error);
    }, this.options.flushInterval || 30000);
  }

  /**
   * Check if event should be sampled
   */
  private shouldSample(): boolean {
    return Math.random() < (this.options.sampleRate || 1.0);
  }

  /**
   * Sanitize data for privacy
   */
  private sanitizeData(data: Record<string, any>): Record<string, any> {
    if (!this.options.privacyMode) {
      return data;
    }

    // Remove potentially sensitive data
    const sanitized: Record<string, any> = {};

    for (const [key, value] of Object.entries(data)) {
      if (typeof value === 'string' && value.length > 50) {
        sanitized[key] = '<redacted>';
      } else if (key.toLowerCase().includes('name') || 
                 key.toLowerCase().includes('email') ||
                 key.toLowerCase().includes('user')) {
        sanitized[key] = '<redacted>';
      } else {
        sanitized[key] = value;
      }
    }

    return sanitized;
  }

  /**
   * Update metrics from event
   */
  private updateMetricsFromEvent(event: TelemetryEvent): void {
    // Update session duration
    this.sessionMetrics.duration = Date.now() - this.sessionMetrics.startTime;
  }

  /**
   * Calculate average latency
   */
  private calculateAverageLatency(): number {
    if (this.latencyMeasurements.length === 0) return 0;

    const sum = this.latencyMeasurements.reduce((a, b) => a + b, 0);
    return sum / this.latencyMeasurements.length;
  }

  /**
   * Update change rate
   */
  private updateChangeRate(): void {
    const now = Date.now();
    const oneMinuteAgo = now - 60000;

    // Remove old timestamps
    this.changeTimestamps = this.changeTimestamps.filter(t => t > oneMinuteAgo);

    // Calculate rate
    this.metrics.changeRate = this.changeTimestamps.length;
  }

  /**
   * Update conflict rate
   */
  private updateConflictRate(): void {
    const now = Date.now();
    const oneMinuteAgo = now - 60000;

    // Remove old timestamps
    this.conflictTimestamps = this.conflictTimestamps.filter(t => t > oneMinuteAgo);

    // Calculate rate
    this.metrics.conflictRate = this.conflictTimestamps.length;
  }

  /**
   * Send telemetry to endpoint
   */
  private async sendTelemetry(events: TelemetryEvent[]): Promise<void> {
    if (!this.options.endpoint) return;

    const response = await fetch(this.options.endpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        events,
        sessionMetrics: this.getSessionMetrics(),
        metrics: this.getMetrics()
      })
    });

    if (!response.ok) {
      throw new Error(`Telemetry send failed: ${response.statusText}`);
    }
  }

  /**
   * Generate session ID
   */
  private generateSessionId(): string {
    return `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
  }

  /**
   * Format bytes for display
   */
  private formatBytes(bytes: number): string {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  }

  /**
   * Calculate reliability percentage
   */
  private calculateReliability(): number {
    const total = this.sessionMetrics.changeCount + this.sessionMetrics.errorCount;
    if (total === 0) return 100;

    return Math.round((this.sessionMetrics.changeCount / total) * 100);
  }

  /**
   * Calculate conflict resolution rate
   */
  private calculateConflictResolutionRate(): number {
    if (this.sessionMetrics.conflictCount === 0) return 100;

    // Assume conflicts are resolved if no errors
    const resolved = this.sessionMetrics.conflictCount - 
                    (this.sessionMetrics.errorCount * 0.1); // Estimate

    return Math.round((resolved / this.sessionMetrics.conflictCount) * 100);
  }

  /**
   * Calculate overall performance score
   */
  private calculatePerformanceScore(): number {
    let score = 100;

    // Deduct for high latency
    if (this.sessionMetrics.averageSyncLatency > 100) {
      score -= Math.min(20, (this.sessionMetrics.averageSyncLatency - 100) / 10);
    }

    // Deduct for conflicts
    if (this.metrics.conflictRate > 1) {
      score -= Math.min(20, this.metrics.conflictRate * 5);
    }

    // Deduct for errors
    if (this.sessionMetrics.errorCount > 0) {
      score -= Math.min(30, this.sessionMetrics.errorCount * 5);
    }

    return Math.max(0, Math.round(score));
  }
}

