import { IndexeddbPersistence } from 'y-indexeddb';
import type { ExperimentCRDT } from './ExperimentCRDT.js';
import type { SyncStatus } from './types.js';

export interface OfflineChange {
  id: string;
  timestamp: number;
  path: string[];
  value: any;
  synced: boolean;
}

export type SyncStatusCallback = (status: SyncStatus) => void;

/**
 * OfflineSync handles offline editing and automatic synchronization
 * when the connection is restored.
 */
export class OfflineSync {
  private persistence: IndexeddbPersistence;
  private pendingChanges: OfflineChange[] = [];
  private syncStatus: SyncStatus = {
    connected: false,
    syncing: false,
    pendingChanges: 0,
    provider: 'offline'
  };
  private statusCallbacks: Set<SyncStatusCallback> = new Set();
  private reconnectTimer: NodeJS.Timeout | null = null;
  private reconnectAttempts = 0;
  private maxReconnectAttempts = 10;
  private reconnectDelay = 1000; // Start with 1 second

  constructor(
    private crdt: ExperimentCRDT,
    private experimentId: string
  ) {
    // Initialize IndexedDB persistence
    this.persistence = new IndexeddbPersistence(experimentId, crdt.getDoc());

    // Set up connection monitoring
    this.setupConnectionMonitoring();

    // Load pending changes from storage
    this.loadPendingChanges();
  }

  /**
   * Track a change made while offline
   */
  trackOfflineChange(path: string[], value: any): void {
    const change: OfflineChange = {
      id: `${Date.now()}-${Math.random()}`,
      timestamp: Date.now(),
      path,
      value,
      synced: false
    };

    this.pendingChanges.push(change);
    this.savePendingChanges();
    this.updateSyncStatus();
  }

  /**
   * Get current sync status
   */
  getSyncStatus(): SyncStatus {
    return { ...this.syncStatus };
  }

  /**
   * Subscribe to sync status changes
   */
  onSyncStatusChange(callback: SyncStatusCallback): () => void {
    this.statusCallbacks.add(callback);

    // Send initial status
    callback(this.getSyncStatus());

    return () => {
      this.statusCallbacks.delete(callback);
    };
  }

  /**
   * Manually trigger sync attempt
   */
  async syncNow(): Promise<void> {
    if (this.syncStatus.syncing) {
      return; // Already syncing
    }

    this.updateSyncStatus({ syncing: true });

    try {
      await this.processPendingChanges();
      this.updateSyncStatus({ 
        syncing: false, 
        lastSyncTime: Date.now(),
        error: undefined 
      });
    } catch (error) {
      this.updateSyncStatus({ 
        syncing: false, 
        error: error.message 
      });
      throw error;
    }
  }

  /**
   * Clear all pending changes
   */
  clearPendingChanges(): void {
    this.pendingChanges = [];
    this.savePendingChanges();
    this.updateSyncStatus();
  }

  /**
   * Get pending changes count
   */
  getPendingChangesCount(): number {
    return this.pendingChanges.filter(c => !c.synced).length;
  }

  /**
   * Get pending changes
   */
  getPendingChanges(): OfflineChange[] {
    return this.pendingChanges.filter(c => !c.synced);
  }

  /**
   * Clean up resources
   */
  destroy(): void {
    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer);
    }

    window.removeEventListener('online', this.handleOnline);
    window.removeEventListener('offline', this.handleOffline);

    this.statusCallbacks.clear();
    this.persistence.destroy();
  }

  /**
   * Set up connection monitoring
   */
  private setupConnectionMonitoring(): void {
    // Monitor online/offline events
    this.handleOnline = this.handleOnline.bind(this);
    this.handleOffline = this.handleOffline.bind(this);

    window.addEventListener('online', this.handleOnline);
    window.addEventListener('offline', this.handleOffline);

    // Check initial connection status
    this.updateConnectionStatus(navigator.onLine);
  }

  /**
   * Handle coming online
   */
  private handleOnline(): void {
    this.updateConnectionStatus(true);
    this.attemptReconnect();
  }

  /**
   * Handle going offline
   */
  private handleOffline(): void {
    this.updateConnectionStatus(false);
    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer);
      this.reconnectTimer = null;
    }
  }

  /**
   * Update connection status
   */
  private updateConnectionStatus(connected: boolean): void {
    const wasConnected = this.syncStatus.connected;
    this.updateSyncStatus({ 
      connected,
      provider: connected ? 'websocket' : 'offline'
    });

    // If we just connected, try to sync
    if (!wasConnected && connected) {
      this.syncNow().catch(error => {
        console.error('Failed to sync after reconnection:', error);
      });
    }
  }

  /**
   * Attempt to reconnect with exponential backoff
   */
  private attemptReconnect(): void {
    if (this.reconnectTimer) {
      return; // Already attempting
    }

    if (this.reconnectAttempts >= this.maxReconnectAttempts) {
      this.updateSyncStatus({ 
        error: 'Max reconnection attempts reached' 
      });
      return;
    }

    this.reconnectTimer = setTimeout(async () => {
      this.reconnectTimer = null;
      this.reconnectAttempts++;

      try {
        // Test connection by attempting sync
        await this.syncNow();

        // Success - reset attempts
        this.reconnectAttempts = 0;
        this.reconnectDelay = 1000;
      } catch (error) {
        // Failed - try again with exponential backoff
        this.reconnectDelay = Math.min(this.reconnectDelay * 2, 30000); // Max 30 seconds
        this.attemptReconnect();
      }
    }, this.reconnectDelay);
  }

  /**
   * Process pending changes
   */
  private async processPendingChanges(): Promise<void> {
    const unsynced = this.pendingChanges.filter(c => !c.synced);

    if (unsynced.length === 0) {
      return;
    }

    // Apply changes to CRDT
    const doc = this.crdt.getDoc();

    await new Promise<void>((resolve, reject) => {
      try {
        doc.transact(() => {
          unsynced.forEach(change => {
            this.crdt.updateFromVisual(change.path, change.value);
            change.synced = true;
          });
        }, 'offline-sync');

        this.savePendingChanges();
        resolve();
      } catch (error) {
        reject(error);
      }
    });

    // Clean up old synced changes (keep last 100 for history)
    const synced = this.pendingChanges.filter(c => c.synced);
    if (synced.length > 100) {
      this.pendingChanges = [
        ...synced.slice(-100),
        ...this.pendingChanges.filter(c => !c.synced)
      ];
      this.savePendingChanges();
    }

    this.updateSyncStatus();
  }

  /**
   * Load pending changes from storage
   */
  private async loadPendingChanges(): Promise<void> {
    try {
      const stored = localStorage.getItem(`psyforge-offline-${this.experimentId}`);
      if (stored) {
        this.pendingChanges = JSON.parse(stored);
        this.updateSyncStatus();
      }
    } catch (error) {
      console.error('Failed to load pending changes:', error);
    }
  }

  /**
   * Save pending changes to storage
   */
  private savePendingChanges(): void {
    try {
      localStorage.setItem(
        `psyforge-offline-${this.experimentId}`,
        JSON.stringify(this.pendingChanges)
      );
    } catch (error) {
      console.error('Failed to save pending changes:', error);

      // If storage is full, remove old synced changes
      const unsynced = this.pendingChanges.filter(c => !c.synced);
      this.pendingChanges = unsynced;

      try {
        localStorage.setItem(
          `psyforge-offline-${this.experimentId}`,
          JSON.stringify(this.pendingChanges)
        );
      } catch (retryError) {
        console.error('Failed to save even after cleanup:', retryError);
      }
    }
  }

  /**
   * Update sync status and notify callbacks
   */
  private updateSyncStatus(updates?: Partial<SyncStatus>): void {
    this.syncStatus = {
      ...this.syncStatus,
      ...updates,
      pendingChanges: this.getPendingChangesCount()
    };

    this.statusCallbacks.forEach(callback => {
      callback(this.getSyncStatus());
    });
  }

  /**
   * Export pending changes for debugging
   */
  exportPendingChanges(): string {
    return JSON.stringify({
      experimentId: this.experimentId,
      pendingChanges: this.pendingChanges,
      syncStatus: this.syncStatus,
      exportTime: new Date().toISOString()
    }, null, 2);
  }
}

