     2→import { ExperimentCRDT } from '../src/ExperimentCRDT';
     3→import { CRDTPerformanceOptimizer } from '../src/CRDTPerformanceOptimizer';
     4→
     5→describe('CRDTPerformanceOptimizer', () => {
     6→  let crdt: ExperimentCRDT;
     7→  let optimizer: CRDTPerformanceOptimizer;
     8→
     9→  beforeEach(() => {
    10→    vi.useFakeTimers();
    11→    
    12→    crdt = new ExperimentCRDT('test-experiment', {
    13→      enableWebRTC: false,
    14→      enableWebSocket: false,
    15→      enableIndexedDB: false
    16→    });
    17→
    18→    optimizer = new CRDTPerformanceOptimizer(crdt, {
    19→      batchTimeout: 50,
    20→      maxBatchSize: 3
    21→    });
    22→  });
    23→
    24→  afterEach(() => {
    25→    vi.useRealTimers();
    26→    optimizer?.destroy();
    27→    crdt?.destroy();
    28→  });
    29→
    30→  describe('batch updates', () => {
    31→    it('should batch multiple updates within timeout window', () => {
    32→      const updateSpy = vi.spyOn(crdt, 'updateFromVisual');
    33→
    34→      // Add updates (less than max batch size to avoid immediate processing)
    35→      optimizer.batchUpdate(['path1'], 'value1');
    36→      optimizer.batchUpdate(['path2'], 'value2');
    37→
    38→      // Updates should not be applied yet
    39→      expect(updateSpy).not.toHaveBeenCalled();
    40→
    41→      // Advance time past batch timeout
    42→      vi.advanceTimersByTime(51);
    43→
    44→      // All updates should be applied
    45→      expect(updateSpy).toHaveBeenCalledTimes(2);
    46→      expect(updateSpy).toHaveBeenCalledWith(['path1'], 'value1');
    47→      expect(updateSpy).toHaveBeenCalledWith(['path2'], 'value2');
    48→    });
    49→
    50→    it('should process batch immediately when max size reached', () => {
    51→      const updateSpy = vi.spyOn(crdt, 'updateFromVisual');
    52→
    53→      // Add updates up to max batch size
    54→      optimizer.batchUpdate(['path1'], 'value1');
    55→      optimizer.batchUpdate(['path2'], 'value2');
    56→      optimizer.batchUpdate(['path3'], 'value3');
    57→
    58→      // Should process immediately without waiting
    59→      expect(updateSpy).toHaveBeenCalledTimes(3);
    60→
    61→      // Add another update
    62→      optimizer.batchUpdate(['path4'], 'value4');
    63→
    64→      // Should not be processed yet
    65→      expect(updateSpy).toHaveBeenCalledTimes(3);
    66→
    67→      // Advance time
    68→      vi.advanceTimersByTime(51);
    69→
    70→      // Now the fourth update should be processed
    71→      expect(updateSpy).toHaveBeenCalledTimes(4);
    72→    });
    73→  });
    74→
    75→  describe('performance metrics', () => {
    76→    it('should track metrics', () => {
    77→      const initialMetrics = optimizer.getMetrics();
    78→      
    79→      expect(initialMetrics).toEqual({
    80→        syncLatency: 0,
    81→        operationCount: 0,
    82→        dataSize: 0,
    83→        compressionRatio: 1,
    84→        batchEfficiency: 1
    85→      });
    86→
    87→      // Perform some operations
    88→      optimizer.batchUpdate(['test'], 'value');
    89→      vi.advanceTimersByTime(51);
    90→
    91→      const updatedMetrics = optimizer.getMetrics();
    92→      expect(updatedMetrics.operationCount).toBeGreaterThan(0);
    93→    });
    94→
    95→    it('should reset metrics', () => {
    96→      // Add some operations
    97→      optimizer.batchUpdate(['test'], 'value');
    98→      vi.advanceTimersByTime(51);
    99→
   100→      const metrics = optimizer.getMetrics();
   101→      expect(metrics.operationCount).toBeGreaterThan(0);
   102→
   103→      // Reset
   104→      optimizer.resetMetrics();
   105→
   106→      const resetMetrics = optimizer.getMetrics();
   107→      expect(resetMetrics.operationCount).toBe(0);
   108→    });
   109→  });
   110→
   111→  describe('data optimization', () => {
   112→    it('should optimize large experiment data', () => {
   113→      const largeExperiment = {
   114→        timeline: Array(100).fill(null).map((_, i) => ({
   115→          id: `trial-${i}`,
   116→          type: 'trial',
   117→          duration: 1000,
   118→          stimuli: [{ type: 'text', content: 'Test' }]
   119→        })),
